  USING (
    EXISTS (
      SELECT 1 FROM meditation_goals
      WHERE meditation_goals.id = daily_completions.goal_id
      AND meditation_goals.user_id = auth.uid()
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM meditation_goals
      WHERE meditation_goals.id = daily_completions.goal_id
