-- ========================================================
-- Commitment Contracts server-side scheduled sweep (Slice Q)
-- ========================================================

-- Allow trusted server contexts (cron/postgres) to run per-user due evaluations,
-- while still enforcing strict user scoping for authenticated app calls.
CREATE OR REPLACE FUNCTION public.evaluate_due_commitment_contracts(
  p_user_id UUID,
  p_max_windows INTEGER DEFAULT 12
)
RETURNS TABLE (
  id TEXT,
  contract_id TEXT,
  user_id UUID,
  window_start TIMESTAMPTZ,
  window_end TIMESTAMPTZ,
  target_count INTEGER,
  actual_count INTEGER,
  grace_days_used INTEGER,
  result TEXT,
  stake_forfeited INTEGER,
  bonus_awarded INTEGER,
  evaluated_at TIMESTAMPTZ
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_now TIMESTAMPTZ := NOW();
  v_contract RECORD;
  v_window_start TIMESTAMPTZ;
  v_window_end TIMESTAMPTZ;
  v_windows_processed INTEGER;
  v_target_with_grace INTEGER;
  v_result TEXT;
  v_stake_forfeited INTEGER;
  v_bonus_awarded INTEGER;
  v_profile RECORD;
  v_success_streak INTEGER;
  v_success_streak_after INTEGER;
  v_multiplier NUMERIC;
  v_eval_id TEXT;
  v_recent_eval RECORD;
  v_is_server_context BOOLEAN := auth.uid() IS NULL AND current_user = 'postgres';
BEGIN
  IF p_user_id IS NULL THEN
    RAISE EXCEPTION 'p_user_id is required';
  END IF;

  IF NOT v_is_server_context
     AND auth.uid() IS DISTINCT FROM p_user_id
     AND auth.role() <> 'service_role' THEN
    RAISE EXCEPTION 'Not authorized to evaluate contracts for this user';
  END IF;

  FOR v_contract IN
    SELECT *
    FROM public.commitment_contracts
    WHERE user_id = p_user_id
      AND status = 'active'
    ORDER BY updated_at ASC
  LOOP
    v_windows_processed := 0;
    v_window_start := v_contract.current_window_start;

    LOOP
      EXIT WHEN v_windows_processed >= GREATEST(1, p_max_windows);

      v_window_end := CASE
        WHEN v_contract.cadence = 'daily' THEN (date_trunc('day', v_window_start) + INTERVAL '1 day' - INTERVAL '1 millisecond')
        ELSE (date_trunc('day', v_window_start) + INTERVAL '7 day' - INTERVAL '1 millisecond')
      END;

      EXIT WHEN v_now <= v_window_end;

      v_target_with_grace := GREATEST(v_contract.target_count - v_contract.grace_days, 0);
      v_result := CASE WHEN v_contract.current_progress >= v_target_with_grace THEN 'success' ELSE 'miss' END;

      v_success_streak := 0;
      FOR v_recent_eval IN
        SELECT result
        FROM public.commitment_contract_evaluations
        WHERE contract_id = v_contract.id
        ORDER BY evaluated_at DESC
      LOOP
        EXIT WHEN v_recent_eval.result <> 'success';
        v_success_streak := v_success_streak + 1;
      END LOOP;

      v_success_streak_after := CASE WHEN v_result = 'success' THEN v_success_streak + 1 ELSE 0 END;
      v_multiplier := CASE
        WHEN v_success_streak_after >= 8 THEN 2
        WHEN v_success_streak_after >= 5 THEN 1.5
        WHEN v_success_streak_after >= 3 THEN 1.25
        ELSE 1
      END;

      v_stake_forfeited := CASE WHEN v_result = 'miss' THEN v_contract.stake_amount ELSE 0 END;
      v_bonus_awarded := CASE
        WHEN v_result = 'success' THEN GREATEST(1, FLOOR(v_contract.stake_amount * 0.1 * v_multiplier)::INTEGER)
        ELSE 0
      END;

      v_eval_id := 'evaluation-' || gen_random_uuid()::TEXT;

      INSERT INTO public.commitment_contract_evaluations (
        id,
        contract_id,
        user_id,
        window_start,
        window_end,
        target_count,
        actual_count,
        grace_days_used,
        result,
        stake_forfeited,
        bonus_awarded,
        evaluated_at
      ) VALUES (
        v_eval_id,
        v_contract.id,
        p_user_id,
        v_window_start,
        v_window_end,
        v_contract.target_count,
        v_contract.current_progress,
        LEAST(v_contract.current_progress, v_contract.grace_days),
        v_result,
        v_stake_forfeited,
        v_bonus_awarded,
        v_now
      );

      SELECT total_points, COALESCE(zen_tokens, 0) AS zen_tokens
      INTO v_profile
      FROM public.gamification_profiles
      WHERE user_id = p_user_id
      FOR UPDATE;

      IF FOUND THEN
        IF v_contract.stake_type = 'gold' THEN
          UPDATE public.gamification_profiles
          SET total_points = GREATEST(0, v_profile.total_points - v_stake_forfeited) + v_bonus_awarded,
              updated_at = NOW()
          WHERE user_id = p_user_id;
        ELSE
          UPDATE public.gamification_profiles
          SET zen_tokens = GREATEST(0, v_profile.zen_tokens - v_stake_forfeited) + v_bonus_awarded,
              updated_at = NOW()
          WHERE user_id = p_user_id;
        END IF;
      END IF;

      UPDATE public.commitment_contracts
      SET current_progress = 0,
          target_count = CASE
            WHEN recovery_mode = 'gentle_ramp' AND v_result = 'success' THEN COALESCE(recovery_original_target_count, target_count)
            ELSE target_count
          END,
          recovery_mode = CASE
            WHEN recovery_mode = 'gentle_ramp' AND v_result = 'success' THEN NULL
            ELSE recovery_mode
          END,
          recovery_original_target_count = CASE
            WHEN recovery_mode = 'gentle_ramp' AND v_result = 'success' THEN NULL
            ELSE recovery_original_target_count
          END,
          recovery_activated_at = CASE
            WHEN recovery_mode = 'gentle_ramp' AND v_result = 'success' THEN NULL
            ELSE recovery_activated_at
          END,
          current_window_start = CASE
            WHEN v_contract.cadence = 'daily' THEN date_trunc('day', v_window_end + INTERVAL '1 second')
            ELSE date_trunc('week', v_window_end + INTERVAL '1 second')
          END,
          miss_count = miss_count + CASE WHEN v_result = 'miss' THEN 1 ELSE 0 END,
          success_count = success_count + CASE WHEN v_result = 'success' THEN 1 ELSE 0 END,
          last_evaluated_at = v_now,
          updated_at = NOW()
      WHERE id = v_contract.id;

      RETURN QUERY
      SELECT
        v_eval_id,
        v_contract.id,
        p_user_id,
        v_window_start,
        v_window_end,
        v_contract.target_count,
        v_contract.current_progress,
        LEAST(v_contract.current_progress, v_contract.grace_days),
        v_result,
        v_stake_forfeited,
        v_bonus_awarded,
        v_now;

      SELECT *
      INTO v_contract
      FROM public.commitment_contracts
      WHERE id = v_contract.id;

      v_window_start := v_contract.current_window_start;
      v_windows_processed := v_windows_processed + 1;
    END LOOP;
  END LOOP;
END;
$$;

CREATE OR REPLACE FUNCTION public.evaluate_due_commitment_contracts_sweep(
  p_max_users INTEGER DEFAULT 200,
  p_max_windows_per_user INTEGER DEFAULT 12
)
RETURNS TABLE (
  users_processed INTEGER,
  evaluations_created INTEGER,
  ran_at TIMESTAMPTZ
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_user RECORD;
  v_users_processed INTEGER := 0;
  v_evaluations_created INTEGER := 0;
  v_row_count INTEGER := 0;
  v_ran_at TIMESTAMPTZ := NOW();
BEGIN
  FOR v_user IN
    SELECT DISTINCT user_id
    FROM public.commitment_contracts
    WHERE status = 'active'
    ORDER BY user_id
    LIMIT GREATEST(1, p_max_users)
  LOOP
    v_users_processed := v_users_processed + 1;

    WITH evaluated AS (
      SELECT id
      FROM public.evaluate_due_commitment_contracts(v_user.user_id, p_max_windows_per_user)
    )
    SELECT COUNT(*)
    INTO v_row_count
    FROM evaluated;

    v_evaluations_created := v_evaluations_created + COALESCE(v_row_count, 0);
  END LOOP;

  RETURN QUERY
  SELECT v_users_processed, v_evaluations_created, v_ran_at;
END;
$$;

REVOKE ALL ON FUNCTION public.evaluate_due_commitment_contracts_sweep(INTEGER, INTEGER) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.evaluate_due_commitment_contracts_sweep(INTEGER, INTEGER) TO service_role;

COMMENT ON FUNCTION public.evaluate_due_commitment_contracts_sweep(INTEGER, INTEGER)
IS 'Server-side sweep that evaluates due windows for active commitment contracts across users; intended for scheduled cron execution.';

DO $$
BEGIN
  IF to_regnamespace('cron') IS NOT NULL THEN
    PERFORM cron.unschedule(jobid)
    FROM cron.job
    WHERE jobname = 'commitment-contracts-due-sweep';

    PERFORM cron.schedule(
      'commitment-contracts-due-sweep',
      '*/15 * * * *',
      $job$SELECT public.evaluate_due_commitment_contracts_sweep(200, 12);$job$
    );
  ELSE
    RAISE NOTICE 'cron extension is not enabled; skipping commitment-contracts-due-sweep schedule setup.';
  END IF;
END;
$$;
-- === END MIGRATION: 0144_contract_due_sweep_schedule.sql ===

-- === BEGIN MIGRATION: 0145_contract_due_sweep_observability.sql ===
-- ========================================================
-- Commitment Contracts sweep observability audit log (Slice R)
-- ========================================================

CREATE TABLE IF NOT EXISTS public.commitment_contract_sweep_runs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  triggered_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  finished_at TIMESTAMPTZ,
  job_source TEXT NOT NULL DEFAULT 'cron' CHECK (job_source IN ('cron', 'manual', 'app')),
  max_users INTEGER NOT NULL,
  max_windows_per_user INTEGER NOT NULL,
  users_processed INTEGER NOT NULL DEFAULT 0,
  evaluations_created INTEGER NOT NULL DEFAULT 0,
  failed_users INTEGER NOT NULL DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'running' CHECK (status IN ('running', 'success', 'partial', 'failed')),
  error_message TEXT,
  details JSONB NOT NULL DEFAULT '{}'::JSONB,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_contract_sweep_runs_triggered_at
  ON public.commitment_contract_sweep_runs (triggered_at DESC);

CREATE INDEX IF NOT EXISTS idx_contract_sweep_runs_status
  ON public.commitment_contract_sweep_runs (status);

ALTER TABLE public.commitment_contract_sweep_runs ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Service role can read sweep run audits" ON public.commitment_contract_sweep_runs;
CREATE POLICY "Service role can read sweep run audits"
  ON public.commitment_contract_sweep_runs
  FOR SELECT
  TO service_role
  USING (TRUE);

DROP POLICY IF EXISTS "Service role can insert sweep run audits" ON public.commitment_contract_sweep_runs;
CREATE POLICY "Service role can insert sweep run audits"
  ON public.commitment_contract_sweep_runs
  FOR INSERT
  TO service_role
  WITH CHECK (TRUE);

DROP POLICY IF EXISTS "Service role can update sweep run audits" ON public.commitment_contract_sweep_runs;
CREATE POLICY "Service role can update sweep run audits"
  ON public.commitment_contract_sweep_runs
  FOR UPDATE
  TO service_role
  USING (TRUE)
  WITH CHECK (TRUE);

GRANT SELECT, INSERT, UPDATE ON public.commitment_contract_sweep_runs TO service_role;

COMMENT ON TABLE public.commitment_contract_sweep_runs
  IS 'Operational audit log for scheduled commitment contract due-window sweep runs.';

CREATE OR REPLACE FUNCTION public.evaluate_due_commitment_contracts_sweep(
  p_max_users INTEGER DEFAULT 200,
  p_max_windows_per_user INTEGER DEFAULT 12
)
RETURNS TABLE (
  users_processed INTEGER,
  evaluations_created INTEGER,
  ran_at TIMESTAMPTZ
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_user RECORD;
  v_users_processed INTEGER := 0;
  v_evaluations_created INTEGER := 0;
  v_failed_users INTEGER := 0;
  v_row_count INTEGER := 0;
  v_ran_at TIMESTAMPTZ := NOW();
  v_run_id UUID;
  v_errors JSONB := '[]'::JSONB;
BEGIN
  INSERT INTO public.commitment_contract_sweep_runs (
    triggered_at,
    job_source,
    max_users,
    max_windows_per_user,
    status
  )
  VALUES (
    v_ran_at,
    CASE WHEN auth.role() = 'service_role' THEN 'manual' ELSE 'cron' END,
    GREATEST(1, p_max_users),
    GREATEST(1, p_max_windows_per_user),
    'running'
  )
  RETURNING id INTO v_run_id;

  FOR v_user IN
    SELECT DISTINCT user_id
    FROM public.commitment_contracts
    WHERE status = 'active'
    ORDER BY user_id
    LIMIT GREATEST(1, p_max_users)
  LOOP
    BEGIN
      v_users_processed := v_users_processed + 1;

      WITH evaluated AS (
        SELECT id
        FROM public.evaluate_due_commitment_contracts(v_user.user_id, p_max_windows_per_user)
      )
      SELECT COUNT(*)
      INTO v_row_count
      FROM evaluated;

      v_evaluations_created := v_evaluations_created + COALESCE(v_row_count, 0);
    EXCEPTION
      WHEN OTHERS THEN
        v_failed_users := v_failed_users + 1;
        v_errors := v_errors || jsonb_build_object(
          'user_id', v_user.user_id,
          'error', SQLERRM,
          'failed_at', NOW()
        );
    END;
  END LOOP;

  UPDATE public.commitment_contract_sweep_runs
  SET finished_at = NOW(),
      users_processed = v_users_processed,
      evaluations_created = v_evaluations_created,
      failed_users = v_failed_users,
      status = CASE
        WHEN v_failed_users = 0 THEN 'success'
        WHEN v_users_processed > v_failed_users THEN 'partial'
        ELSE 'failed'
      END,
      details = jsonb_build_object(
        'errors', v_errors,
        'max_users', GREATEST(1, p_max_users),
        'max_windows_per_user', GREATEST(1, p_max_windows_per_user)
      )
  WHERE id = v_run_id;

  RETURN QUERY
  SELECT v_users_processed, v_evaluations_created, v_ran_at;
EXCEPTION
  WHEN OTHERS THEN
    IF v_run_id IS NOT NULL THEN
      UPDATE public.commitment_contract_sweep_runs
      SET finished_at = NOW(),
          users_processed = v_users_processed,
          evaluations_created = v_evaluations_created,
          failed_users = v_failed_users,
          status = 'failed',
          error_message = SQLERRM,
          details = jsonb_build_object(
            'errors', v_errors,
            'max_users', GREATEST(1, p_max_users),
            'max_windows_per_user', GREATEST(1, p_max_windows_per_user)
          )
      WHERE id = v_run_id;
    END IF;
    RAISE;
END;
$$;

COMMENT ON FUNCTION public.evaluate_due_commitment_contracts_sweep(INTEGER, INTEGER)
IS 'Server-side sweep that evaluates due windows for active commitment contracts across users and records audit telemetry for each run.';
-- === END MIGRATION: 0145_contract_due_sweep_observability.sql ===

-- === BEGIN MIGRATION: 0146_contract_sweep_health_rpc.sql ===
-- Surface non-sensitive contract sweep health telemetry to authenticated clients.
CREATE OR REPLACE FUNCTION public.get_commitment_contract_sweep_health()
RETURNS TABLE (
  status text,
  triggered_at timestamptz,
  finished_at timestamptz,
  users_processed integer,
  evaluations_created integer,
  failed_users integer
)
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT
    run.status::text,
    run.triggered_at,
    run.finished_at,
    run.users_processed,
    run.evaluations_created,
    run.failed_users
  FROM public.commitment_contract_sweep_runs AS run
  ORDER BY run.triggered_at DESC
  LIMIT 1;
$$;

REVOKE ALL ON FUNCTION public.get_commitment_contract_sweep_health() FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.get_commitment_contract_sweep_health() TO authenticated;
GRANT EXECUTE ON FUNCTION public.get_commitment_contract_sweep_health() TO service_role;

COMMENT ON FUNCTION public.get_commitment_contract_sweep_health()
  IS 'Returns a single latest commitment contract sweep run summary for user-facing reliability messaging.';
-- === END MIGRATION: 0146_contract_sweep_health_rpc.sql ===

-- === BEGIN MIGRATION: 0147_contract_reset_guardrails.sql ===
-- Track contract reset guardrails so reset recovery cannot be spammed.

alter table public.commitment_contracts
  add column if not exists reset_count integer not null default 0,
  add column if not exists last_reset_at timestamptz;

update public.commitment_contracts
set
  reset_count = coalesce(reset_count, 0),
  last_reset_at = coalesce(last_reset_at, null)
where true;
