  ADD COLUMN IF NOT EXISTS token_index INTEGER NOT NULL DEFAULT 0,
  ADD COLUMN IF NOT EXISTS hearts INTEGER NOT NULL DEFAULT 5,
  ADD COLUMN IF NOT EXISTS coins INTEGER NOT NULL DEFAULT 0,
