-- =====================================================
-- 5) TRIGGERS
-- =====================================================
CREATE OR REPLACE FUNCTION public.touch_routines_updated_at()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS touch_routines_updated_at ON public.routines;
CREATE TRIGGER touch_routines_updated_at
  BEFORE UPDATE ON public.routines
  FOR EACH ROW
  EXECUTE FUNCTION public.touch_routines_updated_at();

DROP TRIGGER IF EXISTS touch_routine_steps_updated_at ON public.routine_steps;
CREATE TRIGGER touch_routine_steps_updated_at
  BEFORE UPDATE ON public.routine_steps
  FOR EACH ROW
  EXECUTE FUNCTION public.touch_routines_updated_at();

DROP TRIGGER IF EXISTS touch_routine_logs_updated_at ON public.routine_logs;
CREATE TRIGGER touch_routine_logs_updated_at
  BEFORE UPDATE ON public.routine_logs
  FOR EACH ROW
  EXECUTE FUNCTION public.touch_routines_updated_at();

-- =====================================================
-- 6) COMMENTS
-- =====================================================
COMMENT ON TABLE public.routines IS 'User-defined routines that compose existing habits_v2 into ordered flows.';
COMMENT ON TABLE public.routine_steps IS 'Ordered steps linking routines to habits_v2 with display behavior rules.';
COMMENT ON TABLE public.routine_logs IS 'Optional routine-level completion milestones per user/day.';
COMMENT ON COLUMN public.routine_steps.display_mode IS 'Visibility control for rendering a step in routine vs standalone habit lanes.';
-- === END MIGRATION: 0203_routines_foundation.sql ===

-- === BEGIN MIGRATION: 0204_feedback_support_cases.sql ===
-- M31: MVP feedback + support case system (admin + owner scoped)

create table if not exists public.admin_users (
  user_id uuid primary key references auth.users(id) on delete cascade,
  role text not null default 'admin' check (role in ('owner', 'admin')),
  active boolean not null default true,
  created_at timestamptz not null default now()
);

create table if not exists public.case_threads (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  case_type text not null check (case_type in ('feedback', 'support')),
  category text not null,
  subject text not null,
  desired_outcome text,
  status text not null default 'new' check (status in ('new', 'triaged', 'waiting_on_user', 'resolved', 'closed')),
  source_surface text,
  source_route text,
  is_demo boolean not null default false,
  metadata jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  closed_at timestamptz
);

create index if not exists case_threads_user_created_idx on public.case_threads(user_id, created_at desc);
create index if not exists case_threads_status_idx on public.case_threads(status, created_at desc);
create index if not exists case_threads_type_status_idx on public.case_threads(case_type, status, created_at desc);

create table if not exists public.case_messages (
  id uuid primary key default gen_random_uuid(),
  thread_id uuid not null references public.case_threads(id) on delete cascade,
  author_user_id uuid references auth.users(id) on delete set null,
  author_role text not null check (author_role in ('user', 'admin', 'system')),
  message_type text not null check (message_type in ('submission', 'internal_note', 'status_change', 'reply_draft')),
  body text not null,
  metadata jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now()
);

create index if not exists case_messages_thread_created_idx on public.case_messages(thread_id, created_at asc);

create or replace function public.update_case_threads_updated_at()
returns trigger as $$
begin
  new.updated_at = now();
  return new;
end;
$$ language plpgsql;

drop trigger if exists trg_case_threads_updated_at on public.case_threads;
create trigger trg_case_threads_updated_at
before update on public.case_threads
for each row execute function public.update_case_threads_updated_at();

alter table public.admin_users enable row level security;
alter table public.case_threads enable row level security;
alter table public.case_messages enable row level security;

-- Admin users can read their own admin row only.
drop policy if exists "admin_users_select_self" on public.admin_users;
create policy "admin_users_select_self"
  on public.admin_users
  for select
  using (auth.uid() = user_id and active = true);

-- Threads: owner can CRUD own; admins can select/update all.
drop policy if exists "case_threads_owner_select" on public.case_threads;
create policy "case_threads_owner_select"
  on public.case_threads
  for select
  using (auth.uid() = user_id);

drop policy if exists "case_threads_owner_insert" on public.case_threads;
create policy "case_threads_owner_insert"
  on public.case_threads
  for insert
  with check (auth.uid() = user_id);

drop policy if exists "case_threads_owner_update" on public.case_threads;
create policy "case_threads_owner_update"
  on public.case_threads
  for update
  using (auth.uid() = user_id)
  with check (auth.uid() = user_id);

drop policy if exists "case_threads_admin_select_all" on public.case_threads;
create policy "case_threads_admin_select_all"
  on public.case_threads
  for select
  using (
    exists (
      select 1
      from public.admin_users admin_row
      where admin_row.user_id = auth.uid()
        and admin_row.active = true
    )
  );

drop policy if exists "case_threads_admin_update_all" on public.case_threads;
create policy "case_threads_admin_update_all"
  on public.case_threads
  for update
  using (
    exists (
      select 1
      from public.admin_users admin_row
      where admin_row.user_id = auth.uid()
        and admin_row.active = true
    )
  )
  with check (true);

-- Messages: session owner or admin can read; owner/user insert own role; admins can insert notes/status/reply drafts.
drop policy if exists "case_messages_owner_select" on public.case_messages;
create policy "case_messages_owner_select"
  on public.case_messages
  for select
  using (
    exists (
      select 1
      from public.case_threads thread
      where thread.id = case_messages.thread_id
        and thread.user_id = auth.uid()
    )
  );

drop policy if exists "case_messages_admin_select" on public.case_messages;
create policy "case_messages_admin_select"
  on public.case_messages
  for select
  using (
    exists (
      select 1
      from public.admin_users admin_row
      where admin_row.user_id = auth.uid()
        and admin_row.active = true
    )
  );

drop policy if exists "case_messages_owner_insert_submission" on public.case_messages;
create policy "case_messages_owner_insert_submission"
  on public.case_messages
  for insert
  with check (
    author_role = 'user'
    and author_user_id = auth.uid()
    and exists (
      select 1
      from public.case_threads thread
      where thread.id = case_messages.thread_id
        and thread.user_id = auth.uid()
    )
  );

drop policy if exists "case_messages_admin_insert" on public.case_messages;
create policy "case_messages_admin_insert"
  on public.case_messages
  for insert
  with check (
    exists (
      select 1
      from public.admin_users admin_row
      where admin_row.user_id = auth.uid()
        and admin_row.active = true
    )
  );

comment on table public.admin_users is 'App-level admin allowlist for support/feedback inbox access.';
comment on table public.case_threads is 'Shared feedback/support thread envelope for MVP.';
comment on table public.case_messages is 'Messages/events for case threads: submission, notes, status change, manual reply draft.';
-- === END MIGRATION: 0204_feedback_support_cases.sql ===

-- === BEGIN MIGRATION: 0205_feedback_support_owner_update_lockdown.sql ===
-- M31A: Lock down case thread owner updates so status/closure remain admin-controlled.

-- Owners should not update case_threads directly in MVP.
-- This prevents tampering with admin-managed lifecycle fields such as status/closed_at.
DROP POLICY IF EXISTS "case_threads_owner_update" ON public.case_threads;
-- === END MIGRATION: 0205_feedback_support_owner_update_lockdown.sql ===

-- === BEGIN MIGRATION: 0206_feedback_support_message_visibility_and_replies.sql ===
-- M31B: Promote support messaging from MVP drafts to visible two-way replies.
-- Adds explicit user/admin reply types and tightens owner-visible message policy.

ALTER TABLE public.case_messages
  DROP CONSTRAINT IF EXISTS case_messages_message_type_check;

ALTER TABLE public.case_messages
  ADD CONSTRAINT case_messages_message_type_check
  CHECK (
    message_type IN (
      'submission',
      'user_reply',
      'admin_reply',
      'internal_note',
      'status_change',
      'reply_draft'
    )
  );

-- Owners should only see end-user-safe messages.
DROP POLICY IF EXISTS "case_messages_owner_select" ON public.case_messages;
CREATE POLICY "case_messages_owner_select"
  ON public.case_messages
  FOR SELECT
  USING (
    message_type IN ('submission', 'user_reply', 'admin_reply', 'status_change')
    AND EXISTS (
      SELECT 1
      FROM public.case_threads thread
      WHERE thread.id = case_messages.thread_id
        AND thread.user_id = auth.uid()
    )
  );

-- Owners can create initial submissions and follow-up replies only.
DROP POLICY IF EXISTS "case_messages_owner_insert_submission" ON public.case_messages;
CREATE POLICY "case_messages_owner_insert_submission"
  ON public.case_messages
  FOR INSERT
  WITH CHECK (
    author_role = 'user'
    AND author_user_id = auth.uid()
    AND message_type IN ('submission', 'user_reply')
    AND EXISTS (
      SELECT 1
      FROM public.case_threads thread
      WHERE thread.id = case_messages.thread_id
        AND thread.user_id = auth.uid()
    )
  );
-- === END MIGRATION: 0206_feedback_support_message_visibility_and_replies.sql ===

-- === BEGIN MIGRATION: 0207_feedback_support_case_routing_fields.sql ===
-- M31C: Add routing/ops fields for support case assignment and SLA tracking.

ALTER TABLE public.case_threads
  ADD COLUMN IF NOT EXISTS priority text NOT NULL DEFAULT 'normal'
    CHECK (priority IN ('low', 'normal', 'high', 'urgent'));

ALTER TABLE public.case_threads
  ADD COLUMN IF NOT EXISTS assignee_admin_user_id uuid
    REFERENCES public.admin_users(user_id) ON DELETE SET NULL;

ALTER TABLE public.case_threads
  ADD COLUMN IF NOT EXISTS first_response_at timestamptz;

CREATE INDEX IF NOT EXISTS case_threads_priority_status_idx
  ON public.case_threads(priority, status, created_at DESC);

CREATE INDEX IF NOT EXISTS case_threads_assignee_idx
  ON public.case_threads(assignee_admin_user_id, status, created_at DESC);
