-- === BEGIN MIGRATION: 0219_island_run_token_index_40tile_reset.sql ===
-- Migration 0219: Align token_index with 40-tile ring board.
--
-- The Island Run board was resized from 60 tiles to 40 tiles.  Any previously
-- persisted token_index >= 40 is out of range for the new ring; wrap it modulo 40
-- so the token lands on a valid tile on first load without a hard reset.
-- The column has no upper-bound constraint, so this is a safe one-time data fix.

UPDATE public.island_run_runtime_state
SET    token_index = token_index % 40
WHERE  token_index >= 40;

COMMENT ON COLUMN public.island_run_runtime_state.token_index IS
  'Current token tile index on the 40-tile Island Run ring board (wraps 0..39).';
-- === END MIGRATION: 0219_island_run_token_index_40tile_reset.sql ===

-- === BEGIN MIGRATION: 0220_contract_due_eval_rpc_auth_uid_wrapper.sql ===
-- ========================================================
-- Contract due-evaluation RPC app-safe auth.uid() wrapper
-- ========================================================
-- Adds a one-argument overload for authenticated app calls so
-- the caller does not pass user identity from the frontend.

CREATE OR REPLACE FUNCTION public.evaluate_due_commitment_contracts(
  p_max_windows INTEGER DEFAULT 12
)
RETURNS TABLE (
  id TEXT,
  contract_id TEXT,
  user_id UUID,
  window_start TIMESTAMPTZ,
  window_end TIMESTAMPTZ,
  target_count INTEGER,
  actual_count INTEGER,
  grace_days_used INTEGER,
  result TEXT,
  stake_forfeited INTEGER,
  bonus_awarded INTEGER,
  evaluated_at TIMESTAMPTZ
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_auth_uid UUID := auth.uid();
BEGIN
  IF v_auth_uid IS NULL THEN
    IF auth.role() = 'service_role' THEN
      RAISE EXCEPTION 'Service role must call evaluate_due_commitment_contracts(p_user_id, p_max_windows)';
    END IF;
    RAISE EXCEPTION 'Authentication required';
  END IF;

  RETURN QUERY
  SELECT *
  FROM public.evaluate_due_commitment_contracts(v_auth_uid, p_max_windows);
END;
$$;

REVOKE ALL ON FUNCTION public.evaluate_due_commitment_contracts(INTEGER) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.evaluate_due_commitment_contracts(INTEGER) TO authenticated;
GRANT EXECUTE ON FUNCTION public.evaluate_due_commitment_contracts(INTEGER) TO service_role;

COMMENT ON FUNCTION public.evaluate_due_commitment_contracts(INTEGER)
IS 'Authenticated app wrapper for due contract evaluation. Resolves user identity from auth.uid() and delegates to the two-argument evaluator.';
-- === END MIGRATION: 0220_contract_due_eval_rpc_auth_uid_wrapper.sql ===

-- === BEGIN MIGRATION: 0221_contract_due_eval_rpc_auth_uid_wrapper_user_id_ambiguity_fix.sql ===
-- ============================================================================
-- Fix 1-arg evaluate_due_commitment_contracts wrapper user_id ambiguity
-- ============================================================================
-- Replaces the app-facing auth.uid() wrapper with explicit delegated column
-- projection to avoid ambiguous `user_id` binding in overloaded RPC contexts.

CREATE OR REPLACE FUNCTION public.evaluate_due_commitment_contracts(
  p_max_windows INTEGER DEFAULT 12
)
RETURNS TABLE (
  id TEXT,
  contract_id TEXT,
  user_id UUID,
  window_start TIMESTAMPTZ,
  window_end TIMESTAMPTZ,
  target_count INTEGER,
  actual_count INTEGER,
  grace_days_used INTEGER,
  result TEXT,
  stake_forfeited INTEGER,
  bonus_awarded INTEGER,
  evaluated_at TIMESTAMPTZ
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_auth_uid UUID := auth.uid();
BEGIN
  IF v_auth_uid IS NULL THEN
    IF auth.role() = 'service_role' THEN
      RAISE EXCEPTION 'Service role must call evaluate_due_commitment_contracts(p_user_id, p_max_windows)';
    END IF;
    RAISE EXCEPTION 'Authentication required';
  END IF;

  RETURN QUERY
  SELECT
    delegated.id,
    delegated.contract_id,
    delegated.user_id,
    delegated.window_start,
    delegated.window_end,
    delegated.target_count,
    delegated.actual_count,
    delegated.grace_days_used,
    delegated.result,
    delegated.stake_forfeited,
    delegated.bonus_awarded,
    delegated.evaluated_at
  FROM public.evaluate_due_commitment_contracts(v_auth_uid, p_max_windows) AS delegated;
END;
$$;

REVOKE ALL ON FUNCTION public.evaluate_due_commitment_contracts(INTEGER) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.evaluate_due_commitment_contracts(INTEGER) TO authenticated;
GRANT EXECUTE ON FUNCTION public.evaluate_due_commitment_contracts(INTEGER) TO service_role;

COMMENT ON FUNCTION public.evaluate_due_commitment_contracts(INTEGER)
IS 'Authenticated app wrapper for due contract evaluation. Resolves user identity from auth.uid() and delegates to the two-argument evaluator.';
-- === END MIGRATION: 0221_contract_due_eval_rpc_auth_uid_wrapper_user_id_ambiguity_fix.sql ===

-- === BEGIN MIGRATION: 0222_contract_due_eval_2arg_ambiguity_hardening.sql ===
CREATE OR REPLACE FUNCTION public.evaluate_due_commitment_contracts(
  p_user_id UUID,
  p_max_windows INTEGER DEFAULT 12
)
RETURNS TABLE (
  id TEXT,
  contract_id TEXT,
  user_id UUID,
  window_start TIMESTAMPTZ,
  window_end TIMESTAMPTZ,
  target_count INTEGER,
  actual_count INTEGER,
  grace_days_used INTEGER,
  result TEXT,
  stake_forfeited INTEGER,
  bonus_awarded INTEGER,
  evaluated_at TIMESTAMPTZ
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $function$
DECLARE
  v_now TIMESTAMPTZ := NOW();
  v_contract RECORD;
  v_window_start TIMESTAMPTZ;
  v_window_end TIMESTAMPTZ;
  v_windows_processed INTEGER;
  v_target_with_grace INTEGER;
  v_result TEXT;
  v_stake_forfeited INTEGER;
  v_bonus_awarded INTEGER;
  v_profile RECORD;
  v_success_streak INTEGER;
  v_success_streak_after INTEGER;
  v_multiplier NUMERIC;
  v_eval_id TEXT;
  v_recent_eval RECORD;
  v_is_server_context BOOLEAN := auth.uid() IS NULL AND current_user = 'postgres';
  v_is_completing BOOLEAN;
  v_actual_count INTEGER;
  v_new_escalation_level INTEGER;
  v_new_escalation_multiplier NUMERIC;
BEGIN
  IF p_user_id IS NULL THEN
    RAISE EXCEPTION 'p_user_id is required';
  END IF;

  IF NOT v_is_server_context
     AND auth.uid() IS DISTINCT FROM p_user_id
     AND auth.role() <> 'service_role' THEN
    RAISE EXCEPTION 'Not authorized to evaluate contracts for this user';
  END IF;

  FOR v_contract IN
    SELECT cc.*
    FROM public.commitment_contracts AS cc
    WHERE cc.user_id = p_user_id
      AND cc.status = 'active'
    ORDER BY cc.updated_at ASC
  LOOP
    v_windows_processed := 0;
    v_window_start := v_contract.current_window_start;

    LOOP
      EXIT WHEN v_windows_processed >= GREATEST(1, p_max_windows);

      v_window_end := CASE
        WHEN v_contract.cadence = 'daily' THEN (date_trunc('day', v_window_start) + INTERVAL '1 day' - INTERVAL '1 millisecond')
        ELSE (date_trunc('day', v_window_start) + INTERVAL '7 day' - INTERVAL '1 millisecond')
      END;

      IF v_contract.tracking_mode = 'outcome_only' THEN
        EXIT WHEN v_contract.end_at IS NULL OR v_now < v_contract.end_at;
      ELSE
        EXIT WHEN v_now <= v_window_end;
      END IF;

      IF v_contract.tracking_mode = 'outcome_only' THEN
        v_target_with_grace := v_contract.target_count;
        IF v_contract.self_reported_outcome = 'miss' THEN
          v_result := 'miss';
          v_actual_count := 0;
        ELSE
          v_result := 'success';
          v_actual_count := v_contract.target_count;
        END IF;
      ELSE
        v_target_with_grace := CASE
          WHEN v_contract.contract_type = 'reverse'
            THEN v_contract.target_count + v_contract.grace_days
          ELSE GREATEST(v_contract.target_count - v_contract.grace_days, 0)
        END;

        v_result := CASE
          WHEN v_contract.contract_type = 'reverse'
            THEN CASE WHEN v_contract.current_progress <= v_target_with_grace THEN 'success' ELSE 'miss' END
          ELSE CASE WHEN v_contract.current_progress >= v_target_with_grace THEN 'success' ELSE 'miss' END
        END;

        v_actual_count := v_contract.current_progress;
      END IF;

      v_success_streak := 0;
      FOR v_recent_eval IN
        SELECT cce.result
        FROM public.commitment_contract_evaluations AS cce
        WHERE cce.contract_id = v_contract.id
        ORDER BY cce.evaluated_at DESC
      LOOP
        EXIT WHEN v_recent_eval.result <> 'success';
        v_success_streak := v_success_streak + 1;
      END LOOP;

      v_success_streak_after := CASE WHEN v_result = 'success' THEN v_success_streak + 1 ELSE 0 END;

      v_multiplier := CASE
        WHEN v_success_streak_after >= 8 THEN 2
        WHEN v_success_streak_after >= 5 THEN 1.5
        WHEN v_success_streak_after >= 3 THEN 1.25
        ELSE 1
      END;

      v_is_completing := (
        v_contract.end_at IS NOT NULL
        AND v_window_end >= v_contract.end_at
        AND v_result = 'success'
      );

      v_stake_forfeited := CASE WHEN v_result = 'miss' THEN v_contract.stake_amount ELSE 0 END;

      v_bonus_awarded := CASE
        WHEN v_result = 'success'
        THEN GREATEST(1, FLOOR(v_contract.stake_amount * 0.1 * v_multiplier)::INTEGER)
        ELSE 0
      END;

      v_eval_id := 'evaluation-' || gen_random_uuid()::TEXT;

      INSERT INTO public.commitment_contract_evaluations (
        id,
        contract_id,
        user_id,
        window_start,
        window_end,
        target_count,
        actual_count,
        grace_days_used,
        result,
        stake_forfeited,
        bonus_awarded,
        evaluated_at
      ) VALUES (
        v_eval_id,
        v_contract.id,
        p_user_id,
        v_window_start,
        v_window_end,
        v_contract.target_count,
        v_actual_count,
        0,
        v_result,
        v_stake_forfeited,
        v_bonus_awarded,
        v_now
      );

      INSERT INTO public.user_reputation_scores AS urs (
        user_id,
        contracts_started,
        contracts_completed,
        contracts_failed,
        reliability_rating,
        updated_at
      )
      VALUES (
        p_user_id,
        0,
        CASE WHEN v_result = 'success' THEN 1 ELSE 0 END,
        CASE WHEN v_result = 'miss' THEN 1 ELSE 0 END,
        CASE WHEN v_result = 'success' THEN 1.0 ELSE 0.0 END,
        NOW()
      )
      ON CONFLICT ON CONSTRAINT user_reputation_scores_pkey DO UPDATE SET
        contracts_completed = urs.contracts_completed
          + CASE WHEN v_result = 'success' THEN 1 ELSE 0 END,
        contracts_failed = urs.contracts_failed
          + CASE WHEN v_result = 'miss' THEN 1 ELSE 0 END,
        sacred_contracts_kept = urs.sacred_contracts_kept
          + CASE WHEN v_contract.is_sacred AND v_result = 'success' THEN 1 ELSE 0 END,
        updated_at = NOW();

      RETURN QUERY
      SELECT
        v_eval_id,
        v_contract.id,
        p_user_id,
        v_window_start,
        v_window_end,
        v_contract.target_count,
        v_actual_count,
        0,
        v_result,
        v_stake_forfeited,
        v_bonus_awarded,
        v_now;

    END LOOP;
  END LOOP;
END;
$function$;
-- === END MIGRATION: 0222_contract_due_eval_2arg_ambiguity_hardening.sql ===

-- === BEGIN MIGRATION: 0223_dice_regen_state_and_retire_hearts.sql ===
-- Migration: Add dice regeneration state columns
-- This migration adds the dice_regen_state JSONB column to support level-based
-- passive dice regeneration (Monopoly GO style minimum-roll system).
--
-- The regeneration system:
-- - Player level determines a minimum dice threshold (e.g. level 1 = 30 dice)
-- - If the player has fewer dice than the threshold, dice regenerate passively
-- - Full regeneration from 0 to threshold takes 2 hours
-- - If the player already has dice above the threshold, no regeneration occurs
-- - Hearts are fully retired as a currency

-- Add dice_regen_state column to island_run_runtime_state
ALTER TABLE island_run_runtime_state
ADD COLUMN IF NOT EXISTS dice_regen_state jsonb DEFAULT NULL;

-- Set hearts to 0 for all existing rows (hearts retired)
UPDATE island_run_runtime_state
SET runtime_state = jsonb_set(
  runtime_state,
  '{hearts}',
  '0'::jsonb
)
WHERE runtime_state->>'hearts' IS NOT NULL
  AND (runtime_state->>'hearts')::int > 0;

-- Initialize dice_regen_state for existing rows that don't have it
-- Default: level 1 tier (maxDice=30, regenRatePerHour=15)
UPDATE island_run_runtime_state
SET dice_regen_state = jsonb_build_object(
  'maxDice', 30,
  'regenRatePerHour', 15,
  'lastRegenAtMs', extract(epoch from now()) * 1000
)
WHERE dice_regen_state IS NULL;

-- Add comment documenting the column
COMMENT ON COLUMN island_run_runtime_state.dice_regen_state IS
  'Level-based dice regeneration state: {maxDice, regenRatePerHour, lastRegenAtMs}. '
  'Used by the minimum-roll passive regeneration system. '
  'Hearts are fully retired; dice is the sole board energy.';
-- === END MIGRATION: 0223_dice_regen_state_and_retire_hearts.sql ===

-- === BEGIN MIGRATION: 0224_corrective_dice_regen_rollout.sql ===
-- Corrective migration for dice regeneration rollout
-- Previous migration partially applied: dice_regen_state column already exists.
-- This migration finishes the rollout against the real table schema.

-- 1) Retire hearts as a real integer column
UPDATE island_run_runtime_state
SET hearts = 0
WHERE hearts IS NOT NULL
  AND hearts > 0;

-- 2) Initialize dice_regen_state where still missing
UPDATE island_run_runtime_state
SET dice_regen_state = jsonb_build_object(
  'maxDice', 30,
  'regenRatePerHour', 15,
  'lastRegenAtMs', (extract(epoch from now()) * 1000)::bigint
)
WHERE dice_regen_state IS NULL;

-- 3) Add / refresh comment
COMMENT ON COLUMN island_run_runtime_state.dice_regen_state IS
  'Level-based dice regeneration state: {maxDice, regenRatePerHour, lastRegenAtMs}. Used by the minimum-roll passive regeneration system. Hearts are fully retired; dice is the sole board energy.';
-- === END MIGRATION: 0224_corrective_dice_regen_rollout.sql ===

-- === BEGIN MIGRATION: 0225_fix_dice_pool_default.sql ===
-- Migration 0225: Fix incorrect dice_pool column DEFAULT (20 → 30)
--
-- Root cause: Migration 0188 added `dice_pool INTEGER NOT NULL DEFAULT 20`.
-- The correct value is 30, which matches:
--   - ISLAND_RUN_DEFAULT_STARTING_DICE = 30 (islandRunEconomy.ts)
--   - DICE_REGEN_TIERS[0].minDice = 30 (level-1 passive regen threshold)
--
-- Impact of the wrong default:
--   1. All rows created by migration 0188 received dice_pool = 20.
--   2. On game open the UI briefly showed 30 (React useState initial value)
--      before the hydration sync snapped it to 20, causing a visible 20/30 flicker.
--   3. With dice_pool at 20 (below the regen minimum of 30) passive regen
--      should have topped the pool back to 30, but regen is applied on the
--      client side — so affected players were stuck at 20 indefinitely.
--
-- Fix:
--   1. Bring every row below the level-1 minimum (30) up to 30.
--      This is the same corrective action the passive regen system would apply.
--   2. Change the column DEFAULT to 30 so future rows are created correctly.

-- 1) Correct all rows that are still below the level-1 regen minimum of 30.
UPDATE island_run_runtime_state
SET dice_pool = 30
WHERE dice_pool < 30;

-- 2) Fix the column default for future inserts.
ALTER TABLE island_run_runtime_state
  ALTER COLUMN dice_pool SET DEFAULT 30;

COMMENT ON COLUMN island_run_runtime_state.dice_pool IS
  'Current Island Run dice pool available for rolls on the active island. '
  'Minimum level-1 regeneration threshold is 30 (DICE_REGEN_TIERS[0].minDice).';
-- === END MIGRATION: 0225_fix_dice_pool_default.sql ===

-- === BEGIN MIGRATION: 0226_island_run_health_check.sql ===
-- ═══════════════════════════════════════════════════════════════════════════════
-- Island Run 120 — Database Health Check
-- ═══════════════════════════════════════════════════════════════════════════════
-- Run this migration to verify all required tables, columns, and functions
-- for the 120-island game are present in your Supabase instance.
--
-- If any check fails, the entire migration aborts with a descriptive error.
-- On success, a summary row is inserted into a transient temp table you can query.
-- ═══════════════════════════════════════════════════════════════════════════════

DO $$
DECLARE
  _missing_columns TEXT[] := '{}';
  _missing_functions TEXT[] := '{}';
  _col TEXT;
  _fn TEXT;

  -- All required columns on island_run_runtime_state
  -- NOTE: hearts and coins were retired and dropped in migration 0227.
  _required_columns TEXT[] := ARRAY[
    'user_id',
    'created_at',
    'updated_at',
    'current_island_number',
    'first_run_claimed',
    'daily_hearts_claimed_day_key',
    'token_index',
    'island_shards',
    'shard_tier_index',
    'shard_claim_count',
    'shards',
    'shields',
    'spin_tokens',
    'dice_pool',
    'cycle_index',
    'boss_trial_resolved_island_number',
    'active_egg_tier',
    'active_egg_set_at_ms',
    'active_egg_hatch_duration_ms',
    'active_egg_is_dormant',
    'per_island_eggs',
    'island_started_at_ms',
    'island_expires_at_ms',
    'completed_stops_by_island',
    'market_owned_bundles_by_island',
    'diamonds',
    'onboarding_display_name_loop_completed',
    'story_prologue_seen',
    'creature_collection',
    'audio_enabled',
    'runtime_version',
    'creature_treat_inventory',
    'companion_bonus_last_visit_key',
    'active_companion_id',
    'perfect_companion_ids',
    'perfect_companion_reasons',
    'perfect_companion_computed_at_ms',
    'perfect_companion_model_version',
    'perfect_companion_computed_cycle_index',
    'active_stop_index',
    'active_stop_type',
    'stop_states_by_index',
    'stop_build_state_by_index',
    'boss_state',
    'essence',
    'essence_lifetime_earned',
    'essence_lifetime_spent',
    'dice_regen_state',
    'reward_bar_progress',
    'reward_bar_threshold',
    'reward_bar_claim_count_in_event',
    'reward_bar_escalation_tier',
    'reward_bar_last_claim_at_ms',
    'reward_bar_bound_event_id',
    'reward_bar_ladder_id',
    'active_timed_event',
    'active_timed_event_progress',
    'sticker_progress',
    'sticker_inventory',
    'last_writer_device_session_id',
    'stop_tickets_paid_by_island',
    'last_essence_drift_lost'
  ];

  -- Required RPC functions
  _required_functions TEXT[] := ARRAY[
    'island_run_commit_action'
  ];

BEGIN
  -- ─── 1. Check that the main table exists ──────────────────────────────────
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.tables
    WHERE table_schema = 'public'
      AND table_name = 'island_run_runtime_state'
  ) THEN
    RAISE EXCEPTION '[HEALTH CHECK FAILED] Table "public.island_run_runtime_state" does not exist. Run all island_run migrations (0167+).';
  END IF;

  -- ─── 2. Check all required columns exist ──────────────────────────────────
  FOREACH _col IN ARRAY _required_columns
  LOOP
    IF NOT EXISTS (
      SELECT 1 FROM information_schema.columns
      WHERE table_schema = 'public'
        AND table_name = 'island_run_runtime_state'
        AND column_name = _col
    ) THEN
      _missing_columns := array_append(_missing_columns, _col);
    END IF;
  END LOOP;

  IF array_length(_missing_columns, 1) > 0 THEN
    RAISE EXCEPTION '[HEALTH CHECK FAILED] Missing columns on "island_run_runtime_state": %',
      array_to_string(_missing_columns, ', ');
  END IF;

  -- ─── 3. Check dice_pool DEFAULT is 30 (not the old 20) ───────────────────
  IF EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public'
      AND table_name = 'island_run_runtime_state'
      AND column_name = 'dice_pool'
      AND column_default LIKE '%20%'
  ) THEN
    RAISE EXCEPTION '[HEALTH CHECK FAILED] dice_pool DEFAULT is still 20. Run migration 0225_fix_dice_pool_default.sql to correct it to 30.';
  END IF;

  -- ─── 4. Check required RPC functions exist ────────────────────────────────
  FOREACH _fn IN ARRAY _required_functions
  LOOP
    IF NOT EXISTS (
      SELECT 1 FROM information_schema.routines
      WHERE routine_schema = 'public'
        AND routine_name = _fn
    ) THEN
      _missing_functions := array_append(_missing_functions, _fn);
    END IF;
  END LOOP;

  IF array_length(_missing_functions, 1) > 0 THEN
    RAISE EXCEPTION '[HEALTH CHECK FAILED] Missing RPC functions: %',
      array_to_string(_missing_functions, ', ');
  END IF;

  -- ─── 5. Check active_sessions table exists (session locking) ─────────────
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.tables
    WHERE table_schema = 'public'
      AND table_name = 'island_run_active_sessions'
  ) THEN
    RAISE EXCEPTION '[HEALTH CHECK FAILED] Table "public.island_run_active_sessions" does not exist. Run migration 0196.';
  END IF;

  -- ─── 6. Check RLS is enabled on the runtime state table ──────────────────
  IF NOT EXISTS (
    SELECT 1 FROM pg_tables
    WHERE schemaname = 'public'
      AND tablename = 'island_run_runtime_state'
      AND rowsecurity = true
  ) THEN
    RAISE WARNING '[HEALTH CHECK WARNING] RLS is not enabled on "island_run_runtime_state". This may be intentional for development but should be enabled in production.';
  END IF;

  -- ═══ All checks passed ═══════════════════════════════════════════════════
  RAISE NOTICE '✅ Island Run 120 Health Check PASSED — all tables, columns, functions, and defaults are correct.';
END;
$$;
-- === END MIGRATION: 0226_island_run_health_check.sql ===

-- === BEGIN MIGRATION: 0227_retire_hearts_coins_island_run.sql ===
-- Retire `hearts` and `coins` columns from the island_run_runtime_state table.
--
-- Context: Hearts and coins were fully retired from gameplay in earlier releases
-- (see CANONICAL_GAMEPLAY_CONTRACT.md §3). The active currencies are now
-- dice, essence, shards, diamonds, and spin tokens. The columns were zeroed out
-- in 0224_corrective_dice_regen_rollout.sql but kept nullable so older clients
-- would not break. Client code no longer reads or writes these columns as of
-- this release, so the columns can now be safely dropped.
--
-- Client-side fallback: the hydration code intentionally tolerates missing
-- `hearts` / `coins` keys (they were removed from the SELECT list and default
-- fallbacks in the matching PR), so older rows surviving this migration
-- will continue to hydrate cleanly for one release cycle.
--
-- Note: `daily_hearts_claimed_day_key` is NOT dropped here — it is a legacy
-- name for a daily-claim tracker (no longer tied to hearts the currency).
-- Renaming it is a separate future cleanup.

ALTER TABLE island_run_runtime_state
  DROP COLUMN IF EXISTS hearts,
  DROP COLUMN IF EXISTS coins;
-- === END MIGRATION: 0227_retire_hearts_coins_island_run.sql ===

-- === BEGIN MIGRATION: 0228_island_run_action_log_client_action_id_to_text.sql ===
-- Fix: Change client_action_id from uuid to text in island_run_action_log
-- and in the island_run_commit_action RPC.
--
-- The client generates descriptive action IDs of the form
-- "runtime-<userId>-<counter>-<version>-<hash>" which are not valid UUIDs.
-- Passing these to the RPC caused:
--   "invalid input syntax for type uuid: ..."
-- breaking reset-progress and every other runtime snapshot commit.

-- ─── 1. Drop the existing unique constraint (depends on the uuid column) ────
ALTER TABLE public.island_run_action_log
  DROP CONSTRAINT IF EXISTS island_run_action_log_client_action_unique;

-- ─── 2. Alter the column type from uuid to text ────────────────────────────
ALTER TABLE public.island_run_action_log
  ALTER COLUMN client_action_id TYPE text USING client_action_id::text;

-- ─── 3. Re-create the unique constraint on the text column ─────────────────
ALTER TABLE public.island_run_action_log
  ADD CONSTRAINT island_run_action_log_client_action_unique
    UNIQUE (user_id, client_action_id);

-- ─── 4. Drop old RPC signature (uuid) and recreate with text ───────────────
-- Must drop all grants/comments that reference the old signature first.
DROP FUNCTION IF EXISTS public.island_run_commit_action(text, bigint, text, jsonb, uuid);

CREATE OR REPLACE FUNCTION public.island_run_commit_action(
  p_device_session_id text,
  p_expected_runtime_version bigint,
  p_action_type text,
  p_action_payload jsonb,
  p_client_action_id text default null
)
RETURNS TABLE (
  status text,
  runtime_version bigint,
  latest_state jsonb,
  server_message text
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_existing public.island_run_runtime_state%rowtype;
  v_next public.island_run_runtime_state%rowtype;
  v_now timestamptz := now();
  v_expected bigint := greatest(0, coalesce(p_expected_runtime_version, 0));
  v_existing_log public.island_run_action_log%rowtype;
  v_response jsonb;
  -- Scalar extraction variables — avoids 42P01 errors from composite
  -- variable field access inside RETURN QUERY SELECT (PG parser resolves
  -- the composite var name as a relation reference even with parens).
  v_tmp_status text;
  v_tmp_version bigint;
  v_tmp_state jsonb;
BEGIN
  IF v_user_id IS NULL AND auth.role() <> 'service_role' THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF p_device_session_id IS NULL OR char_length(trim(p_device_session_id)) = 0 THEN
    RETURN QUERY SELECT 'invalid'::text, 0::bigint, NULL::jsonb, 'device_session_id is required'::text;
    RETURN;
  END IF;

  IF coalesce(nullif(trim(p_action_type), ''), 'runtime_snapshot_upsert') <> 'runtime_snapshot_upsert' THEN
    RETURN QUERY SELECT 'invalid'::text, 0::bigint, NULL::jsonb, 'Unsupported action_type'::text;
    RETURN;
  END IF;

  IF p_client_action_id IS NOT NULL AND char_length(trim(p_client_action_id)) > 0 THEN
    SELECT *
      INTO v_existing_log
      FROM public.island_run_action_log
     WHERE user_id = v_user_id
       AND client_action_id = p_client_action_id
     LIMIT 1;

    IF FOUND THEN
      v_tmp_status  := coalesce((v_existing_log).status, 'duplicate');
      v_tmp_version := coalesce((v_existing_log).applied_runtime_version, 0);
      v_tmp_state   := (v_existing_log).response_json -> 'latest_state';
      RETURN QUERY
      SELECT
        v_tmp_status::text,
        v_tmp_version::bigint,
        v_tmp_state::jsonb,
        'Duplicate action id; returning cached response.'::text;
      RETURN;
    END IF;
  END IF;

  SELECT *
    INTO v_existing
    FROM public.island_run_runtime_state
   WHERE user_id = v_user_id
   FOR UPDATE;

  IF NOT FOUND THEN
    IF v_expected <> 0 THEN
      RETURN QUERY SELECT 'conflict'::text, 0::bigint, NULL::jsonb, 'Runtime row missing for expected version.'::text;
      RETURN;
    END IF;

    v_next := jsonb_populate_record(NULL::public.island_run_runtime_state, coalesce(p_action_payload, '{}'::jsonb));
  ELSE
    IF coalesce(v_existing.runtime_version, 0) <> v_expected THEN
      v_tmp_version := coalesce((v_existing).runtime_version, 0);
      v_tmp_state   := to_jsonb(v_existing);
      RETURN QUERY
      SELECT
        'conflict'::text,
        v_tmp_version::bigint,
        v_tmp_state,
        'Runtime version mismatch.'::text;
      RETURN;
    END IF;

    v_next := jsonb_populate_record(v_existing, coalesce(p_action_payload, '{}'::jsonb));
    DELETE FROM public.island_run_runtime_state WHERE user_id = v_user_id;
  END IF;

  v_next.user_id := v_user_id;
  v_next.runtime_version := v_expected + 1;
  v_next.last_writer_device_session_id := trim(p_device_session_id);
  v_next.updated_at := v_now;

  INSERT INTO public.island_run_runtime_state
  SELECT (v_next).*;

  v_response := jsonb_build_object(
    'status', 'applied',
    'runtime_version', v_next.runtime_version,
    'latest_state', to_jsonb(v_next),
    'server_message', 'Action applied.'
  );

  INSERT INTO public.island_run_action_log (
    user_id,
    device_session_id,
    client_action_id,
    action_type,
    expected_runtime_version,
    applied_runtime_version,
    status,
    payload_json,
    response_json
  ) VALUES (
    v_user_id,
    trim(p_device_session_id),
    p_client_action_id,
    'runtime_snapshot_upsert',
    v_expected,
    v_next.runtime_version,
    'applied',
    coalesce(p_action_payload, '{}'::jsonb),
    v_response
  );

  v_tmp_version := v_next.runtime_version;
  v_tmp_state   := to_jsonb(v_next);

  RETURN QUERY
  SELECT
    'applied'::text,
    v_tmp_version::bigint,
    v_tmp_state,
    'Action applied.'::text;
END;
$$;

REVOKE ALL ON FUNCTION public.island_run_commit_action(text, bigint, text, jsonb, text) FROM public;
GRANT EXECUTE ON FUNCTION public.island_run_commit_action(text, bigint, text, jsonb, text) TO authenticated;
GRANT EXECUTE ON FUNCTION public.island_run_commit_action(text, bigint, text, jsonb, text) TO service_role;

COMMENT ON FUNCTION public.island_run_commit_action(text, bigint, text, jsonb, text) IS
  'Island Run server-authoritative action commit entrypoint with optimistic version checks and idempotency key support.';
-- === END MIGRATION: 0228_island_run_action_log_client_action_id_to_text.sql ===

-- === BEGIN MIGRATION: 0229_add_missing_island_run_columns.sql ===
-- Migration 0229: Add missing columns to island_run_runtime_state and fix
-- the active_stop_type constraint.
--
-- Context:
-- 1. stop_tickets_paid_by_island and last_essence_drift_lost were persisted
--    by the client in the action-commit payload (JSONB) but had no matching
--    database columns.  jsonb_populate_record silently dropped these keys,
--    causing data loss when the user switched devices.
-- 2. The active_stop_type constraint allowed 'breathing' but the client
--    renamed that stop kind to 'mystery'.  Writing 'mystery' to the DB
--    would violate the old constraint.

-- ─── 1. Add stop_tickets_paid_by_island column ─────────────────────────────
ALTER TABLE public.island_run_runtime_state
  ADD COLUMN IF NOT EXISTS stop_tickets_paid_by_island jsonb NOT NULL DEFAULT '{}'::jsonb;

COMMENT ON COLUMN public.island_run_runtime_state.stop_tickets_paid_by_island IS
  'Per-island ledger of stop indices (1-4) whose essence ticket has been paid.';

-- ─── 2. Add last_essence_drift_lost column ──────────────────────────────────
ALTER TABLE public.island_run_runtime_state
  ADD COLUMN IF NOT EXISTS last_essence_drift_lost integer NOT NULL DEFAULT 0;

COMMENT ON COLUMN public.island_run_runtime_state.last_essence_drift_lost IS
  'Essence lost to drift on last hydration/session-open (UI notification). 0 = no drift.';

-- ─── 3. Fix active_stop_type constraint ─────────────────────────────────────
-- The client renamed 'breathing' → 'mystery'. Accept both for backward compat.
ALTER TABLE public.island_run_runtime_state
  DROP CONSTRAINT IF EXISTS island_run_runtime_state_active_stop_type_check;

ALTER TABLE public.island_run_runtime_state
  ADD CONSTRAINT island_run_runtime_state_active_stop_type_check
    CHECK (active_stop_type IN ('hatchery', 'habit', 'mystery', 'breathing', 'wisdom', 'boss'));
