-- === BEGIN MIGRATION: 0230_add_bonus_tile_charge_by_island.sql ===
-- Migration 0230: Add bonus_tile_charge_by_island column to
-- island_run_runtime_state so the 9-hit accumulator ledger persists across
-- devices. Unblocks the bonus-tile renderer wiring (contract §5E) and the
-- `resetBonusTileChargeForIsland` call in `performIslandTravel`.
--
-- Shape (client-side `BonusTileChargeByIsland`, see `islandRunBonusTile.ts`):
--   {
--     "<islandNumber>": {
--       "<tileIndex>": <charge in 0..8>
--     },
--     ...
--   }
-- Outer key: island number as string (matches the rest of the per-island maps
-- — `completed_stops_by_island`, `stop_tickets_paid_by_island`,
-- `market_owned_bundles_by_island`). Inner key: ring tile index. Value: the
-- current charge count; zero entries are pruned on write.

ALTER TABLE public.island_run_runtime_state
  ADD COLUMN IF NOT EXISTS bonus_tile_charge_by_island jsonb NOT NULL DEFAULT '{}'::jsonb;

COMMENT ON COLUMN public.island_run_runtime_state.bonus_tile_charge_by_island IS
  'Per-(island, tileIndex) charge ledger for the glowing bonus tile. 1..8 charges; cleared to 0 on the 9th landing (release). See islandRunBonusTile.ts BONUS_CHARGE_TARGET.';
-- === END MIGRATION: 0230_add_bonus_tile_charge_by_island.sql ===

-- === BEGIN MIGRATION: 0230_drop_island_run_commit_action_uuid_overload.sql ===
-- Fix: Drop the stale uuid-signature overload of island_run_commit_action.
--
-- Migration 0228 changed p_client_action_id from uuid → text and issued a
-- DROP FUNCTION for the old uuid signature, but the drop was not applied to
-- production.  As a result two overloads now coexist:
--
--   island_run_commit_action(..., p_client_action_id => uuid)   ← stale / 0217
--   island_run_commit_action(..., p_client_action_id => text)   ← current / 0228
--
-- PostgreSQL cannot resolve which candidate to call and raises:
--   "Could not choose the best candidate function between: ..."
-- whenever the reset-gameplay (or any other) path invokes the RPC.
--
-- This migration unconditionally drops the old uuid overload so that only the
-- text-parameter version remains.

DROP FUNCTION IF EXISTS public.island_run_commit_action(text, bigint, text, jsonb, uuid);
-- === END MIGRATION: 0230_drop_island_run_commit_action_uuid_overload.sql ===

-- === BEGIN MIGRATION: 0231_add_minigame_tickets_by_event.sql ===
-- Migration 0231: Add minigame_tickets_by_event column to
-- island_run_runtime_state so per-event minigame ticket balances persist
-- across devices.
--
-- Phase 1 of the Minigame & Events Consolidation Plan
-- (docs/gameplay/MINIGAME_EVENTS_CONSOLIDATION_PLAN.md §7).
--
-- Shape (client-side `IslandRunGameStateRecord.minigameTicketsByEvent`):
--   {
--     "<eventId>": <ticket count>,
--     ...
--   }
-- eventId matches the canonical timed-event union:
--   feeding_frenzy | lucky_spin | space_excavator | companion_feast
-- Value: non-negative integer count of unused tickets for that event.
--
-- Zero balances are pruned on write. Column is additive only — nothing reads
-- from it yet (that lands in Phase 6/7 when Stripe top-ups + event-gated
-- launches ship); Phase 1 just reserves the column so later client writes
-- have somewhere to land.

ALTER TABLE public.island_run_runtime_state
  ADD COLUMN IF NOT EXISTS minigame_tickets_by_event jsonb NOT NULL DEFAULT '{}'::jsonb;

COMMENT ON COLUMN public.island_run_runtime_state.minigame_tickets_by_event IS
  'Per-timed-event minigame ticket ledger. Outer key: eventId (feeding_frenzy | lucky_spin | space_excavator | companion_feast). Value: non-negative integer count. Zero entries are pruned on write. See docs/gameplay/MINIGAME_EVENTS_CONSOLIDATION_PLAN.md §7 and src/config/islandRunFeatureFlags.ts.';
-- === END MIGRATION: 0231_add_minigame_tickets_by_event.sql ===

