-- === BEGIN MIGRATION: 0257_combined_journey_reward_claims.sql ===
-- ============================================================
-- COMBINED JOURNEY REWARD CLAIMS
-- Migration 0257: Idempotency ledger for Combined Journey Level
--   threshold chests (Combined Journey Level feature, slice R3).
--
-- Schema only. No rewards are granted by this migration. The
-- server-authoritative claim path (a SECURITY DEFINER RPC that
-- grants exactly one reward per chest) lands in slice R4.
--
-- Idempotency backbone: PRIMARY KEY (user_id, threshold_level)
-- guarantees a given threshold chest can be claimed at most once
-- per user, regardless of client retries or races.
--
-- Security: RLS grants users SELECT on their own rows only. There
-- is intentionally NO insert/update/delete policy, so clients can
-- never write the ledger directly — writes flow exclusively through
-- the R4 claim RPC / service-role path.
-- ============================================================

CREATE TABLE IF NOT EXISTS public.combined_journey_reward_claims (
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  threshold_level INTEGER NOT NULL CHECK (threshold_level >= 1),
  reward_kind TEXT NOT NULL CHECK (reward_kind IN ('dice', 'essence', 'egg', 'reroll_capacity')),
  reward_amount INTEGER NOT NULL DEFAULT 0 CHECK (reward_amount >= 0),
  claimed_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (user_id, threshold_level)
);

-- Recent-claims lookups for telemetry / support.
CREATE INDEX IF NOT EXISTS idx_combined_journey_reward_claims_claimed_at
  ON public.combined_journey_reward_claims(claimed_at DESC);

ALTER TABLE public.combined_journey_reward_claims ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "own_combined_journey_reward_claims_select" ON public.combined_journey_reward_claims;
CREATE POLICY "own_combined_journey_reward_claims_select" ON public.combined_journey_reward_claims
  FOR SELECT USING (auth.uid() = user_id);

COMMENT ON TABLE public.combined_journey_reward_claims IS
  'Idempotency ledger for Combined Journey Level threshold chests. One row per (user, threshold_level); a row means that chest''s single reward was granted. Writes occur only via the server-authoritative claim path (slice R4).';
COMMENT ON COLUMN public.combined_journey_reward_claims.threshold_level IS
  'The Combined Journey Level whose chest was claimed.';
COMMENT ON COLUMN public.combined_journey_reward_claims.reward_kind IS
  'The single reward granted for this chest: dice | essence | egg | reroll_capacity.';
COMMENT ON COLUMN public.combined_journey_reward_claims.reward_amount IS
  'Amount granted for currency-style rewards (dice/essence/reroll_capacity); eggs use the configured egg grant.';
-- === END MIGRATION: 0257_combined_journey_reward_claims.sql ===

-- === BEGIN MIGRATION: 0258_combined_journey_reward_claim_rpc.sql ===
-- ============================================================
-- COMBINED JOURNEY REWARD CLAIM RPC
-- Migration 0258: Server-authoritative, idempotent claim of a
--   Combined Journey Level threshold chest (feature slice R4).
--
-- Builds on 0257 (the claims ledger). The reward kind/amount is
-- resolved here in SQL from the threshold level alone, so clients
-- cannot choose their own reward — they only say which threshold
-- they are claiming. Idempotency is enforced by the ledger's
-- PRIMARY KEY (user_id, threshold_level) via ON CONFLICT DO NOTHING.
--
-- This mirrors combinedJourneyRewardLadder.ts exactly:
--   even threshold -> dice,    amount = 10 + 5 * floor(level / 5)
--   odd  threshold -> essence, amount =  5 + 3 * floor(level / 5)
-- Keep the two in lockstep when the ladder changes.
-- ============================================================

CREATE OR REPLACE FUNCTION public.claim_combined_journey_reward(p_threshold_level INTEGER)
RETURNS TABLE(claimed BOOLEAN, reward_kind TEXT, reward_amount INTEGER)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_band INTEGER;
  v_kind TEXT;
  v_amount INTEGER;
  v_inserted BOOLEAN := false;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF p_threshold_level IS NULL OR p_threshold_level < 1 THEN
    RAISE EXCEPTION 'threshold_level must be >= 1';
  END IF;

  -- Deterministic reward resolution (mirror of combinedJourneyRewardLadder.ts).
  v_band := p_threshold_level / 5; -- integer floor division for positive values
  IF p_threshold_level % 2 = 0 THEN
    v_kind := 'dice';
    v_amount := 10 + 5 * v_band;
  ELSE
    v_kind := 'essence';
    v_amount := 5 + 3 * v_band;
  END IF;

  INSERT INTO public.combined_journey_reward_claims (user_id, threshold_level, reward_kind, reward_amount)
  VALUES (v_user_id, p_threshold_level, v_kind, v_amount)
  ON CONFLICT (user_id, threshold_level) DO NOTHING
  RETURNING true INTO v_inserted;

  IF COALESCE(v_inserted, false) THEN
    RETURN QUERY SELECT true, v_kind, v_amount;
    RETURN;
  END IF;

  -- Already claimed: return the previously granted reward so callers stay idempotent.
  RETURN QUERY
    SELECT false, c.reward_kind, c.reward_amount
    FROM public.combined_journey_reward_claims c
    WHERE c.user_id = v_user_id
      AND c.threshold_level = p_threshold_level;
END;
$$;

REVOKE ALL ON FUNCTION public.claim_combined_journey_reward(INTEGER) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.claim_combined_journey_reward(INTEGER) TO authenticated;

COMMENT ON FUNCTION public.claim_combined_journey_reward(INTEGER) IS
  'Idempotently claims one Combined Journey Level threshold chest. Resolves the reward server-side from the threshold level and records it once per (user, threshold_level). Returns claimed=false with the existing reward when already claimed.';
-- === END MIGRATION: 0258_combined_journey_reward_claim_rpc.sql ===

-- === BEGIN MIGRATION: 0259_combined_journey_reward_ladder_eggs.sql ===
-- ============================================================
-- COMBINED JOURNEY REWARD LADDER — ADD EGGS
-- Migration 0259: extends the reward ladder so threshold chests
--   can grant eggs (feature slice R6). Replaces the 0258 resolver.
--
-- Mirrors combinedJourneyRewardLadder.ts exactly:
--   level % 3 == 0          -> egg,     amount = 1
--   else even threshold     -> dice,    amount = 10 + 5 * floor(level / 5)
--   else odd threshold      -> essence, amount =  5 + 3 * floor(level / 5)
--
-- Idempotency, auth, and the ledger insert are unchanged from 0258. Reroll-
-- capacity rewards are added in a later slice. Safe to re-map now: the rewards
-- feature is still flag-gated off, so no production claims exist yet.
-- ============================================================

CREATE OR REPLACE FUNCTION public.claim_combined_journey_reward(p_threshold_level INTEGER)
RETURNS TABLE(claimed BOOLEAN, reward_kind TEXT, reward_amount INTEGER)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_band INTEGER;
  v_kind TEXT;
  v_amount INTEGER;
  v_inserted BOOLEAN := false;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF p_threshold_level IS NULL OR p_threshold_level < 1 THEN
    RAISE EXCEPTION 'threshold_level must be >= 1';
  END IF;

  -- Deterministic reward resolution (mirror of combinedJourneyRewardLadder.ts).
  v_band := p_threshold_level / 5; -- integer floor division for positive values
  IF p_threshold_level % 3 = 0 THEN
    v_kind := 'egg';
    v_amount := 1;
  ELSIF p_threshold_level % 2 = 0 THEN
    v_kind := 'dice';
    v_amount := 10 + 5 * v_band;
  ELSE
    v_kind := 'essence';
    v_amount := 5 + 3 * v_band;
  END IF;

  INSERT INTO public.combined_journey_reward_claims (user_id, threshold_level, reward_kind, reward_amount)
  VALUES (v_user_id, p_threshold_level, v_kind, v_amount)
  ON CONFLICT (user_id, threshold_level) DO NOTHING
  RETURNING true INTO v_inserted;

  IF COALESCE(v_inserted, false) THEN
    RETURN QUERY SELECT true, v_kind, v_amount;
    RETURN;
  END IF;

  -- Already claimed: return the previously granted reward so callers stay idempotent.
  RETURN QUERY
    SELECT false, c.reward_kind, c.reward_amount
    FROM public.combined_journey_reward_claims c
    WHERE c.user_id = v_user_id
      AND c.threshold_level = p_threshold_level;
END;
$$;

REVOKE ALL ON FUNCTION public.claim_combined_journey_reward(INTEGER) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.claim_combined_journey_reward(INTEGER) TO authenticated;
-- === END MIGRATION: 0259_combined_journey_reward_ladder_eggs.sql ===

-- === BEGIN MIGRATION: 0260_island_run_bonus_max_dice_column.sql ===
