-- === BEGIN MIGRATION: 0261_combined_journey_reward_ladder_capacity.sql ===
-- ============================================================
-- COMBINED JOURNEY REWARD LADDER — ADD REROLL CAPACITY
-- Migration 0261: completes the reward ladder with reroll-capacity
--   upgrades (feature slice R7). Replaces the 0259 resolver.
--
-- Mirrors combinedJourneyRewardLadder.ts exactly, in priority order:
--   level % 5 == 0  -> reroll_capacity, amount = 5
--   else level % 3  -> egg,             amount = 1
--   else even       -> dice,            amount = 10 + 5 * floor(level / 5)
--   else odd        -> essence,         amount =  5 + 3 * floor(level / 5)
--
-- Idempotency, auth, and the ledger insert are unchanged. Safe to re-map: the
-- rewards feature is still flag-gated off, so no production claims exist yet.
-- ============================================================

CREATE OR REPLACE FUNCTION public.claim_combined_journey_reward(p_threshold_level INTEGER)
RETURNS TABLE(claimed BOOLEAN, reward_kind TEXT, reward_amount INTEGER)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_band INTEGER;
  v_kind TEXT;
  v_amount INTEGER;
  v_inserted BOOLEAN := false;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF p_threshold_level IS NULL OR p_threshold_level < 1 THEN
    RAISE EXCEPTION 'threshold_level must be >= 1';
  END IF;

  -- Deterministic reward resolution (mirror of combinedJourneyRewardLadder.ts).
  v_band := p_threshold_level / 5; -- integer floor division for positive values
  IF p_threshold_level % 5 = 0 THEN
    v_kind := 'reroll_capacity';
    v_amount := 5;
  ELSIF p_threshold_level % 3 = 0 THEN
    v_kind := 'egg';
    v_amount := 1;
  ELSIF p_threshold_level % 2 = 0 THEN
    v_kind := 'dice';
    v_amount := 10 + 5 * v_band;
  ELSE
    v_kind := 'essence';
    v_amount := 5 + 3 * v_band;
  END IF;

  INSERT INTO public.combined_journey_reward_claims (user_id, threshold_level, reward_kind, reward_amount)
  VALUES (v_user_id, p_threshold_level, v_kind, v_amount)
  ON CONFLICT (user_id, threshold_level) DO NOTHING
  RETURNING true INTO v_inserted;

  IF COALESCE(v_inserted, false) THEN
    RETURN QUERY SELECT true, v_kind, v_amount;
    RETURN;
  END IF;

  -- Already claimed: return the previously granted reward so callers stay idempotent.
  RETURN QUERY
    SELECT false, c.reward_kind, c.reward_amount
    FROM public.combined_journey_reward_claims c
    WHERE c.user_id = v_user_id
      AND c.threshold_level = p_threshold_level;
END;
$$;

REVOKE ALL ON FUNCTION public.claim_combined_journey_reward(INTEGER) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.claim_combined_journey_reward(INTEGER) TO authenticated;
-- === END MIGRATION: 0261_combined_journey_reward_ladder_capacity.sql ===

-- === BEGIN MIGRATION: 0262_combined_journey_reward_baseline.sql ===
-- ============================================================
-- COMBINED JOURNEY REWARD BASELINE
-- Migration 0262: per-user launch baseline so existing players
--   only receive chests for levels reached AFTER the feature
--   goes live (feature slice R8).
--
-- The baseline is the player's Combined Journey Level the first
-- time they open the overlay post-launch. Claimable thresholds
-- are then restricted to levels strictly above the baseline, so
-- accumulated pre-launch progress does not dump a pile of chests.
--
-- Set once and never changed (ON CONFLICT DO NOTHING). RLS lets a
-- user read their own baseline; writes happen only via the
-- SECURITY DEFINER ensure RPC.
-- ============================================================

CREATE TABLE IF NOT EXISTS public.combined_journey_reward_baseline (
  user_id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  baseline_level INTEGER NOT NULL DEFAULT 0 CHECK (baseline_level >= 0),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE public.combined_journey_reward_baseline ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "own_combined_journey_reward_baseline_select" ON public.combined_journey_reward_baseline;
CREATE POLICY "own_combined_journey_reward_baseline_select" ON public.combined_journey_reward_baseline
  FOR SELECT USING (auth.uid() = user_id);

CREATE OR REPLACE FUNCTION public.ensure_combined_journey_baseline(p_level INTEGER)
RETURNS INTEGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_baseline INTEGER;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  INSERT INTO public.combined_journey_reward_baseline (user_id, baseline_level)
  VALUES (v_user_id, GREATEST(0, COALESCE(p_level, 0)))
  ON CONFLICT (user_id) DO NOTHING;

  SELECT baseline_level INTO v_baseline
    FROM public.combined_journey_reward_baseline
   WHERE user_id = v_user_id;

  RETURN COALESCE(v_baseline, 0);
END;
$$;

REVOKE ALL ON FUNCTION public.ensure_combined_journey_baseline(INTEGER) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.ensure_combined_journey_baseline(INTEGER) TO authenticated;

COMMENT ON TABLE public.combined_journey_reward_baseline IS
  'Per-user Combined Journey Level baseline captured at first post-launch overlay open. Chests are only offered for thresholds above this level.';
COMMENT ON FUNCTION public.ensure_combined_journey_baseline(INTEGER) IS
  'Idempotently records (once) the caller''s journey-level baseline and returns the effective baseline level.';
-- === END MIGRATION: 0262_combined_journey_reward_baseline.sql ===

-- === BEGIN MIGRATION: 0263_combined_journey_level_persistence.sql ===
-- ============================================================
-- COMBINED JOURNEY LEVEL PERSISTENCE
-- Migration 0263: persist a write-through snapshot of each user's
--   derived Combined Journey Level so the leaderboard (a cross-user
--   server query) can rank by the canonical progression metric.
--
-- Background: the Combined Journey Level (see
--   src/features/gamification/level-worlds/services/combinedJourneyLevel.ts)
--   is DERIVED from durable milestones and is the canonical score
--   for player rank and the leaderboard. It is computed client-side
--   and was previously never persisted, so the leaderboard could not
--   order by it. These columns hold a snapshot written through when a
--   user views their dual-track progress.
--
-- These values are display/ranking only. They are always recomputable
-- from milestones and are NOT an authoritative economy balance — the
-- accrued XP/gold economy (total_xp / total_points) is unchanged.
--
-- Convergence: existing users default to (level 1, xp 0) and populate
-- their real value the next time they open Game Progress. No accurate
-- server-side backfill is possible because the inputs are aggregated
-- client-side; a backfill job can be added later if needed.
-- ============================================================

ALTER TABLE public.gamification_profiles
  ADD COLUMN IF NOT EXISTS combined_journey_level INT NOT NULL DEFAULT 1,
  ADD COLUMN IF NOT EXISTS combined_journey_xp INT NOT NULL DEFAULT 0;

-- Leaderboard ordering: highest journey xp first, then level, then a
-- deterministic user_id tiebreaker. Partial index matches the
-- leaderboard's gamification_enabled filter.
CREATE INDEX IF NOT EXISTS idx_gamification_profiles_combined_journey
  ON public.gamification_profiles (combined_journey_xp DESC, combined_journey_level DESC, user_id ASC)
  WHERE gamification_enabled = true;

COMMENT ON COLUMN public.gamification_profiles.combined_journey_level IS
  'Write-through snapshot of the derived Combined Journey Level (combinedJourneyLevel.ts). Display/leaderboard only; recomputable from milestones.';
COMMENT ON COLUMN public.gamification_profiles.combined_journey_xp IS
  'Write-through snapshot of derived Combined Journey XP; canonical leaderboard score. Display/ranking only.';
-- === END MIGRATION: 0263_combined_journey_level_persistence.sql ===

-- === BEGIN MIGRATION: 0264_island_run_tech_collection_grid.sql ===
-- Cross-device persistence for the Island Run "tech build" pickup grid.
-- Items picked up from board tiles snap into a per-island 3×3 grid; completing
-- a row/column/diagonal (or the full board) pays out dice. Persist both the
-- collected slots and the already-rewarded line indices so the grid survives
-- reloads and syncs across devices without double-paying line rewards.

alter table if exists island_run_runtime_state
  add column if not exists tech_collection_by_island jsonb not null default '{}'::jsonb;

alter table if exists island_run_runtime_state
  add column if not exists tech_collection_rewarded_lines_by_island jsonb not null default '{}'::jsonb;

comment on column island_run_runtime_state.tech_collection_by_island is
  'Per-island picked-up tech grid. Key = island number string, value = array of collected 3x3 slot indices (0-8).';

comment on column island_run_runtime_state.tech_collection_rewarded_lines_by_island is
  'Per-island ledger of tech-grid line indices (0-7) that already paid a row/column/diagonal completion reward.';
-- === END MIGRATION: 0264_island_run_tech_collection_grid.sql ===

-- === BEGIN MIGRATION: 0265_island_run_narrative_seen_state.sql ===
-- 0265_island_run_narrative_seen_state.sql
-- Cross-device narrative beat/episode "seen" ledger for Island Run.
--
-- This is non-gameplay presentation state: it records which one-time narrative
-- beats and story episodes a player has already been shown so they are not
-- replayed. localStorage remains the offline-immediate mirror; this column is
-- the canonical, device-syncing copy that the runtime state record reads and
-- writes through the existing single-writer persistence path.
--
-- Shape: { "beats": { "<beatId>": <epoch_ms> }, "episodes": { "<episodeId>": <epoch_ms> } }

alter table public.island_run_runtime_state
  add column if not exists narrative_seen_state jsonb not null default '{}'::jsonb;

comment on column public.island_run_runtime_state.narrative_seen_state is
  'Cross-device narrative seen-ledger: { beats: {beatId: epochMs}, episodes: {episodeId: epochMs} }. Non-gameplay presentation state.';
-- === END MIGRATION: 0265_island_run_narrative_seen_state.sql ===

-- === BEGIN MIGRATION: 0265_island_run_technology_unlocks.sql ===
alter table if exists public.island_run_runtime_state
  add column if not exists technology_unlocks_by_id jsonb not null default '{}'::jsonb;

comment on column public.island_run_runtime_state.technology_unlocks_by_id is
  'Global durable Island Run expedition technology unlocks keyed by technology id (for example the-concord).';
-- === END MIGRATION: 0265_island_run_technology_unlocks.sql ===

-- === BEGIN MIGRATION: 0266_tip_of_day_log.sql ===
-- Tip of the Day — AI Coach.
-- One row per user per local day records which "Tip of the Day" variation was
-- shown, which habit it was about, the generated card deck (for history /
-- future personalisation), and any action the user took. The unique
-- (user_id, shown_on) index enforces "one tip per day".

create table if not exists public.tip_of_day_log (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  -- Local calendar date (YYYY-MM-DD) the tip was shown to the user.
  shown_on date not null,
  variation text not null check (variation in ('reshape_struggling', 'habit_science', 'environment_cue')),
  -- The habit the tip focused on, when applicable.
  habit_id uuid references public.habits_v2(id) on delete set null,
  -- The full generated card deck, kept for history and future tuning.
  payload jsonb not null default '{}'::jsonb,
  -- Whether the deck came from the AI or the deterministic fallback.
  source text not null default 'fallback' check (source in ('openai', 'fallback')),
  -- What the user did with the tip: 'applied', 'captured', 'dismissed', null = unseen action.
  action_taken text check (action_taken in ('applied', 'captured', 'dismissed')),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists tip_of_day_log_user_id_idx on public.tip_of_day_log(user_id);
create index if not exists tip_of_day_log_habit_id_idx on public.tip_of_day_log(habit_id);

-- One tip per user per day.
create unique index if not exists tip_of_day_log_user_day_idx
  on public.tip_of_day_log(user_id, shown_on);

-- Reuse the shared touch trigger from 0148_habit_improvement_analysis.sql.
drop trigger if exists trg_touch_tip_of_day_log on public.tip_of_day_log;
create trigger trg_touch_tip_of_day_log
before update on public.tip_of_day_log
for each row execute function public.touch_habit_analysis_updated_at();

alter table public.tip_of_day_log enable row level security;

create policy "tip of day log owned by user"
on public.tip_of_day_log
for all
using (auth.uid() = user_id)
with check (auth.uid() = user_id);
-- === END MIGRATION: 0266_tip_of_day_log.sql ===

-- === BEGIN MIGRATION: 0267_habit_insights.sql ===
-- Habit insights — quick "what got in the way?" / "what triggered it?" captures.
-- Logged from the Today screen when the user skips (or acts on) a struggling
-- habit. Each row records the cue tags they tapped and an optional note. These
-- feed the "Tip of the Day — AI Coach" reshape variation so its advice is based
-- on the user's own reported cues, not just adherence numbers.

create table if not exists public.habit_insights (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  habit_id uuid not null references public.habits_v2(id) on delete cascade,
  -- Local calendar date (YYYY-MM-DD) the insight was captured.
  captured_on date not null,
  -- One-tap cue chips, e.g. {'tired','scrolling'}.
  cue_tags text[] not null default '{}',
  -- Optional free-text insight in the user's own words.
  note text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists habit_insights_user_id_idx on public.habit_insights(user_id);
create index if not exists habit_insights_habit_id_idx on public.habit_insights(habit_id);
create index if not exists habit_insights_habit_captured_idx
  on public.habit_insights(habit_id, captured_on desc);

-- Reuse the shared touch trigger from 0148_habit_improvement_analysis.sql.
drop trigger if exists trg_touch_habit_insights on public.habit_insights;
create trigger trg_touch_habit_insights
before update on public.habit_insights
for each row execute function public.touch_habit_analysis_updated_at();

alter table public.habit_insights enable row level security;

create policy "habit insights owned by user"
on public.habit_insights
for all
using (auth.uid() = user_id)
with check (auth.uid() = user_id);
-- === END MIGRATION: 0267_habit_insights.sql ===

-- === BEGIN MIGRATION: 0268_tip_of_day_followup.sql ===
-- Tip of the Day follow-up — "did you try yesterday's tip?" outcome.
-- Recorded on the *previous* tip's row when the user answers the check-in card
-- at the top of the next day's tip. Lets the coach learn what actually worked.

alter table public.tip_of_day_log
  add column if not exists followup_result text
    check (followup_result in ('worked', 'partly', 'not_yet', 'didnt_work')),
  add column if not exists followup_at timestamptz;
-- === END MIGRATION: 0268_tip_of_day_followup.sql ===

-- === BEGIN MIGRATION: 0269_secure_habit_adjustments_rls.sql ===
-- Secure public.habit_adjustments.
--
-- Ownership chain:
-- habit_adjustments.habit_id
--   -> habits_v2.id
--   -> habits_v2.user_id
--
-- A signed-in user may access an adjustment only when the referenced
-- habit belongs to auth.uid().

alter table public.habit_adjustments
  enable row level security;

-- Anonymous clients should have no direct access to this table.
revoke all privileges
  on table public.habit_adjustments
  from anon;

-- RLS governs ordinary row operations, but TRUNCATE bypasses RLS.
-- REFERENCES and TRIGGER are also unnecessary for normal app clients.
revoke truncate, references, trigger
  on table public.habit_adjustments
  from authenticated;

-- Retain only the row operations required by authenticated app clients.
grant select, insert, update, delete
  on table public.habit_adjustments
  to authenticated;

drop policy if exists "Users can read own habit adjustments"
  on public.habit_adjustments;

create policy "Users can read own habit adjustments"
  on public.habit_adjustments
  for select
  to authenticated
  using (
    exists (
      select 1
      from public.habits_v2 as habit
      where habit.id = habit_adjustments.habit_id
        and habit.user_id = auth.uid()
    )
  );

drop policy if exists "Users can create own habit adjustments"
  on public.habit_adjustments;

create policy "Users can create own habit adjustments"
  on public.habit_adjustments
  for insert
  to authenticated
  with check (
    exists (
      select 1
      from public.habits_v2 as habit
      where habit.id = habit_adjustments.habit_id
        and habit.user_id = auth.uid()
    )
  );

drop policy if exists "Users can update own habit adjustments"
  on public.habit_adjustments;

create policy "Users can update own habit adjustments"
  on public.habit_adjustments
  for update
  to authenticated
  using (
    exists (
      select 1
      from public.habits_v2 as habit
      where habit.id = habit_adjustments.habit_id
        and habit.user_id = auth.uid()
    )
  )
  with check (
    exists (
      select 1
      from public.habits_v2 as habit
      where habit.id = habit_adjustments.habit_id
        and habit.user_id = auth.uid()
    )
  );

drop policy if exists "Users can delete own habit adjustments"
  on public.habit_adjustments;

create policy "Users can delete own habit adjustments"
  on public.habit_adjustments
  for delete
  to authenticated
  using (
    exists (
      select 1
      from public.habits_v2 as habit
      where habit.id = habit_adjustments.habit_id
        and habit.user_id = auth.uid()
    )
  );
-- === END MIGRATION: 0269_secure_habit_adjustments_rls.sql ===

-- === BEGIN MIGRATION: 0270_add_companion_feast_progress_by_event.sql ===
