-- === BEGIN MIGRATION: 0273_add_fortune_engine_progress_by_event.sql ===
-- Migration 0273: Add canonical Island Run Fortune Engine progress ledger.
--
-- The Fortune Engine replaces the Lucky Spin placeholder on the `lucky_spin`
-- timed-event rotation slot. Stores per-timed-event campaign state keyed by
-- the runtime event id: reward-track event points, collected Fortune Core
-- fragment ids (3x3 jackpot grid), claimed milestone ids, total launches,
-- best run score, the daily free Golden Launch day key, and the finale
-- trophy flag.

ALTER TABLE public.island_run_runtime_state
  ADD COLUMN IF NOT EXISTS fortune_engine_progress_by_event jsonb NOT NULL DEFAULT '{}'::jsonb;

COMMENT ON COLUMN public.island_run_runtime_state.fortune_engine_progress_by_event IS
  'Canonical Fortune Engine progress ledger keyed by timed-event runtime event id. Stores eventPoints, fragmentIds, claimedMilestoneIds, totalLaunches, bestRunScore, goldenLaunchDayKey, finaleCompleted, and updatedAtMs for resume.';
-- === END MIGRATION: 0273_add_fortune_engine_progress_by_event.sql ===

-- === BEGIN MIGRATION: 0274_island_run_runtime_state_realtime.sql ===
-- ========================================================
-- Migration 0274: Broadcast island_run_runtime_state changes over realtime.
-- Clients subscribe to their own row (RLS-scoped) so a device converges as
-- soon as another device commits a newer runtime snapshot, instead of
-- waiting for the next focus/visibility event.
-- ========================================================

do $$
begin
  -- Add the table to the realtime publication when it is not already
  -- published (idempotent so re-running the migration set is safe, and a
  -- no-op on projects where the publication is FOR ALL TABLES).
  if exists (
    select 1 from pg_publication where pubname = 'supabase_realtime' and puballtables = false
  ) and not exists (
    select 1
      from pg_publication_tables
     where pubname = 'supabase_realtime'
       and schemaname = 'public'
       and tablename = 'island_run_runtime_state'
  ) then
    alter publication supabase_realtime add table public.island_run_runtime_state;
  end if;
end;
$$;

-- postgres_changes UPDATE payloads need the full new row; the default
-- replica identity only ships the primary key on updates from some paths.
alter table public.island_run_runtime_state replica identity full;
-- === END MIGRATION: 0274_island_run_runtime_state_realtime.sql ===

-- === BEGIN MIGRATION: 0275_log_retention_auto_cleanup.sql ===
-- ========================================================
-- LOG RETENTION AUTO-CLEANUP
-- Migration 0275: Scheduled cleanup of operational log tables
--
-- Context: island_run_action_log stores a full runtime-state
-- snapshot in payload_json AND response_json for every game
-- action (see 0217). The log's only read path is idempotent
-- replay of a recently retried client_action_id, so rows older
-- than a couple of days are dead weight. Left unchecked it grew
-- to ~1.9 GB and tripped the free-tier db size quota
-- (exceed_db_size_quota), taking the whole project down.
-- telemetry_events and pg_cron's own job_run_details history
-- (the due-sweep in 0144 runs every 15 minutes) grow unbounded
-- for the same reason.
-- ========================================================

DO $$
BEGIN
  IF to_regnamespace('cron') IS NOT NULL THEN
    -- Island Run action log: only needed for short-window idempotent
    -- retries; 48 hours is generous.
    PERFORM cron.unschedule(jobid)
    FROM cron.job
    WHERE jobname = 'island-run-action-log-retention';

    PERFORM cron.schedule(
      'island-run-action-log-retention',
      '10 3 * * *',
      $job$DELETE FROM public.island_run_action_log WHERE created_at < now() - interval '48 hours';$job$
    );

    -- Telemetry events: keep 30 days of raw events for stats/rollups.
    PERFORM cron.unschedule(jobid)
    FROM cron.job
    WHERE jobname = 'telemetry-events-retention';

    PERFORM cron.schedule(
      'telemetry-events-retention',
      '15 3 * * *',
      $job$DELETE FROM public.telemetry_events WHERE occurred_at < now() - interval '30 days';$job$
    );

    -- pg_cron run history: with a job every 15 minutes this table
    -- accumulates ~35k rows/year and is never pruned by pg_cron itself.
    PERFORM cron.unschedule(jobid)
    FROM cron.job
    WHERE jobname = 'cron-job-run-details-retention';

    PERFORM cron.schedule(
      'cron-job-run-details-retention',
      '20 3 * * *',
      $job$DELETE FROM cron.job_run_details WHERE end_time < now() - interval '3 days';$job$
    );
  ELSE
    RAISE NOTICE 'cron extension is not enabled; skipping log retention schedule setup.';
  END IF;
END;
$$;
-- === END MIGRATION: 0275_log_retention_auto_cleanup.sql ===

-- === BEGIN MIGRATION: 0276_telemetry_admin_rollups.sql ===
-- ========================================================
-- TELEMETRY ADMIN ROLLUPS
-- Migration 0276: Daily aggregation of telemetry_events for the
-- admin-only telemetry dashboard.
--
-- Raw telemetry_events are pruned after 30 days (migration 0275).
-- This table preserves the statistical value forever at a few KB
-- per day: one row per (day, event_type) with counts and unique
-- users. A nightly pg_cron job re-aggregates the trailing days so
-- late-arriving events are captured before the raw rows expire.
-- ========================================================

CREATE TABLE IF NOT EXISTS public.telemetry_daily_rollups (
  day DATE NOT NULL,
  event_type TEXT NOT NULL,
  event_count INTEGER NOT NULL DEFAULT 0,
  unique_users INTEGER NOT NULL DEFAULT 0,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (day, event_type)
);

COMMENT ON TABLE public.telemetry_daily_rollups
IS 'Daily per-event-type aggregates of telemetry_events; admin-only. Survives raw event pruning.';

ALTER TABLE public.telemetry_daily_rollups ENABLE ROW LEVEL SECURITY;

REVOKE ALL ON TABLE public.telemetry_daily_rollups FROM PUBLIC;
GRANT SELECT ON TABLE public.telemetry_daily_rollups TO authenticated;
GRANT ALL ON TABLE public.telemetry_daily_rollups TO service_role;

DROP POLICY IF EXISTS "telemetry_daily_rollups_admin_select" ON public.telemetry_daily_rollups;
CREATE POLICY "telemetry_daily_rollups_admin_select"
  ON public.telemetry_daily_rollups
  FOR SELECT
  USING (
    EXISTS (
      SELECT 1
      FROM public.admin_users admin_row
      WHERE admin_row.user_id = auth.uid()
        AND admin_row.active = TRUE
    )
  );

-- Admins can also read raw events (recent-activity feed in the
-- dashboard). Users could previously only read their own.
DROP POLICY IF EXISTS "telemetry_events_admin_select_all" ON public.telemetry_events;
CREATE POLICY "telemetry_events_admin_select_all"
  ON public.telemetry_events
  FOR SELECT
  USING (
    EXISTS (
      SELECT 1
      FROM public.admin_users admin_row
      WHERE admin_row.user_id = auth.uid()
        AND admin_row.active = TRUE
    )
  );

-- Re-aggregates the trailing p_lookback_days of raw events into the
-- rollup table. Idempotent: recomputed days are overwritten.
CREATE OR REPLACE FUNCTION public.rollup_telemetry_daily(p_lookback_days INTEGER DEFAULT 3)
RETURNS VOID
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  INSERT INTO public.telemetry_daily_rollups (day, event_type, event_count, unique_users, updated_at)
  SELECT
    (occurred_at AT TIME ZONE 'utc')::date AS day,
    event_type,
    COUNT(*)::integer,
    COUNT(DISTINCT user_id)::integer,
    NOW()
  FROM public.telemetry_events
  WHERE occurred_at >= NOW() - MAKE_INTERVAL(days => GREATEST(COALESCE(p_lookback_days, 3), 1))
  GROUP BY 1, 2
  ON CONFLICT (day, event_type) DO UPDATE
    SET event_count = EXCLUDED.event_count,
        unique_users = EXCLUDED.unique_users,
        updated_at = EXCLUDED.updated_at;
$$;

REVOKE ALL ON FUNCTION public.rollup_telemetry_daily(INTEGER) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.rollup_telemetry_daily(INTEGER) TO service_role;

COMMENT ON FUNCTION public.rollup_telemetry_daily(INTEGER)
IS 'Upserts daily telemetry_events aggregates into telemetry_daily_rollups; intended for scheduled cron execution.';

-- Backfill everything still present in telemetry_events at migration
-- time (raw retention starts pruning at 30 days, but older rows may
-- still exist when this first runs).
SELECT public.rollup_telemetry_daily(365);

-- Nightly at 02:45, before the 03:15 telemetry retention delete from
-- migration 0275, so no raw day expires without being rolled up.
DO $$
BEGIN
  IF to_regnamespace('cron') IS NOT NULL THEN
    PERFORM cron.unschedule(jobid)
    FROM cron.job
    WHERE jobname = 'telemetry-daily-rollup';

    PERFORM cron.schedule(
      'telemetry-daily-rollup',
      '45 2 * * *',
      $job$SELECT public.rollup_telemetry_daily(3);$job$
    );
  ELSE
    RAISE NOTICE 'cron extension is not enabled; skipping telemetry-daily-rollup schedule setup.';
  END IF;
END;
$$;
-- === END MIGRATION: 0276_telemetry_admin_rollups.sql ===

-- === BEGIN MIGRATION: 0277_task_tower_sessions.sql ===
-- ========================================================
-- TASK TOWER SESSIONS
-- Migration 0277: Server-side session telemetry for the
-- Task Tower mini-game (docs/gameplay/TASK_TOWER_V2_PLAN.md).
--
-- Context: the habit-game reward ledger (gold/dice/tokens) is
-- client-side localStorage by design, but Task Tower graduates
-- to public access in this release and needs durable, per-user
-- session records: one row per open, updated with final stats
-- when the player leaves through the rewards screen. Rows with
-- a NULL completed_at are abandoned sessions — useful signal on
-- their own. The game treats these writes as best-effort: an
-- offline or failed insert never blocks play (the local session
-- log remains the fallback).
--
-- Idempotent: safe to re-run.
-- ========================================================

CREATE TABLE IF NOT EXISTS public.task_tower_sessions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL REFERENCES auth.users (id) ON DELETE CASCADE,
  entered_at timestamptz NOT NULL DEFAULT now(),
  completed_at timestamptz,
  tower_size integer NOT NULL DEFAULT 0,
  queued_count integer NOT NULL DEFAULT 0,
  blocks_cleared integer NOT NULL DEFAULT 0,
  storeys_cleared integer NOT NULL DEFAULT 0,
  coins_earned integer NOT NULL DEFAULT 0,
  dice_earned integer NOT NULL DEFAULT 0,
  tokens_earned integer NOT NULL DEFAULT 0,
  max_combo integer NOT NULL DEFAULT 0,
  duration_seconds integer NOT NULL DEFAULT 0,
  all_clear boolean NOT NULL DEFAULT false,
  created_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS task_tower_sessions_user_entered_idx
  ON public.task_tower_sessions (user_id, entered_at DESC);

ALTER TABLE public.task_tower_sessions ENABLE ROW LEVEL SECURITY;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_policies
    WHERE schemaname = 'public'
      AND tablename = 'task_tower_sessions'
      AND policyname = 'task_tower_sessions_select_own'
  ) THEN
    CREATE POLICY task_tower_sessions_select_own
      ON public.task_tower_sessions
      FOR SELECT
      USING (auth.uid() = user_id);
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM pg_policies
    WHERE schemaname = 'public'
      AND tablename = 'task_tower_sessions'
      AND policyname = 'task_tower_sessions_insert_own'
  ) THEN
    CREATE POLICY task_tower_sessions_insert_own
      ON public.task_tower_sessions
      FOR INSERT
      WITH CHECK (auth.uid() = user_id);
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM pg_policies
    WHERE schemaname = 'public'
      AND tablename = 'task_tower_sessions'
      AND policyname = 'task_tower_sessions_update_own'
  ) THEN
    CREATE POLICY task_tower_sessions_update_own
      ON public.task_tower_sessions
      FOR UPDATE
      USING (auth.uid() = user_id)
      WITH CHECK (auth.uid() = user_id);
  END IF;
END
$$;

-- Sessions are lightweight telemetry; keep a year of history at most so the
-- table can't quietly eat the db quota (see 0275 for the cron pattern).
DO $$
BEGIN
  IF to_regnamespace('cron') IS NOT NULL THEN
    PERFORM cron.unschedule(jobid)
    FROM cron.job
    WHERE jobname = 'task-tower-sessions-retention';

    PERFORM cron.schedule(
      'task-tower-sessions-retention',
      '20 3 * * *',
      $job$DELETE FROM public.task_tower_sessions WHERE entered_at < now() - interval '365 days';$job$
    );
  END IF;
END
$$;
-- === END MIGRATION: 0277_task_tower_sessions.sql ===
